def stage61_admin_token_value() -> str:
    for name in STAGE61_ADMIN_TOKEN_ENV_NAMES:
        value = (os.getenv(name, "") or "").strip()
        if value:
            return value
    return ""


def stage61_admin_token_configured() -> bool:
    return bool(stage61_admin_token_value())


def stage61_admin_access_enforcement_enabled() -> bool:
    # Stage 61 deliberately defaults to enforced mode. If the token is missing,
    # protected admin surfaces fail closed with a clear 503 instead of staying public.
    raw = (os.getenv("REPLIQ_ADMIN_ACCESS_ENFORCEMENT", "true") or "true").strip().lower()
    return raw not in {"0", "false", "no", "off", "disabled", "report_only"}


def stage61_path_requires_admin(path: str) -> bool:
    clean = (path or "").rstrip("/") or "/"
    return clean in STAGE61_PROTECTED_EXACT_PATHS


def stage61_query_token(request: Request) -> str:
    for key in STAGE61_ADMIN_QUERY_KEYS:
        value = (request.query_params.get(key) or "").strip()
        if value:
            return value
    return ""


def stage61_request_token(request: Request) -> str:
    for key in STAGE61_ADMIN_HEADER_KEYS:
        value = (request.headers.get(key) or "").strip()
        if value:
            return value
    auth = (request.headers.get("authorization") or "").strip()
    if auth.lower().startswith("bearer "):
        return auth[7:].strip()
    # Legacy Stage 61 cookie remains accepted for backwards compatibility, but
    # Stage 62 browser login writes a signed session cookie instead of the raw token.
    cookie_value = (request.cookies.get(STAGE61_ADMIN_COOKIE_NAME) or "").strip()
    if cookie_value:
        return cookie_value
    return stage61_query_token(request)


def stage61_token_valid(candidate: str) -> bool:
    expected = stage61_admin_token_value()
    if not expected or not candidate:
        return False
    try:
        return hmac.compare_digest(str(candidate), str(expected))
    except Exception:
        return False


def stage62_session_max_age_seconds() -> int:
    raw = (os.getenv("REPLIQ_ADMIN_SESSION_MAX_AGE_SECONDS", "") or "").strip()
    if raw:
        try:
            return max(300, min(int(raw), 60 * 60 * 24 * 14))
        except Exception:
            pass
    return STAGE62_ADMIN_SESSION_MAX_AGE_SECONDS


def stage62_session_secret() -> str:
    # The shared admin token is the root secret for the MVP admin session layer.
    # A separate REPLIQ_ADMIN_SESSION_SECRET may be added later without changing callers.
    return (os.getenv("REPLIQ_ADMIN_SESSION_SECRET", "") or stage61_admin_token_value() or "").strip()


def stage62_b64url_encode(value: bytes) -> str:
    return base64.urlsafe_b64encode(value).decode("ascii").rstrip("=")


def stage62_b64url_decode(value: str) -> bytes:
    value = (value or "").strip()
    value += "=" * ((4 - len(value) % 4) % 4)
    return base64.urlsafe_b64decode(value.encode("ascii"))


def stage62_session_signature(payload_b64: str) -> str:
    secret = stage62_session_secret()
    if not secret:
        return ""
    return hmac.new(secret.encode("utf-8"), payload_b64.encode("ascii"), hashlib.sha256).hexdigest()


def stage62_make_admin_session_cookie(tenant_id: str = TENANT_ID_DEFAULT) -> str:
    now = int(datetime.utcnow().timestamp())
    max_age = stage62_session_max_age_seconds()
    payload = {
        "v": STAGE62_ADMIN_SESSION_VERSION,
        "type": "admin_session",
        "tenant_id": (tenant_id or TENANT_ID_DEFAULT).strip() or TENANT_ID_DEFAULT,
        "iat": now,
        "exp": now + max_age,
    }
    raw = json.dumps(payload, ensure_ascii=False, separators=(",", ":")).encode("utf-8")
    payload_b64 = stage62_b64url_encode(raw)
    sig = stage62_session_signature(payload_b64)
    return f"{payload_b64}.{sig}" if sig else ""


def stage62_parse_admin_session_cookie(raw_cookie: str) -> Optional[Dict[str, Any]]:
    raw_cookie = (raw_cookie or "").strip()
    if not raw_cookie or "." not in raw_cookie:
        return None
    payload_b64, sig = raw_cookie.rsplit(".", 1)
    expected = stage62_session_signature(payload_b64)
    if not expected or not hmac.compare_digest(sig, expected):
        return None
    try:
        payload = json.loads(stage62_b64url_decode(payload_b64).decode("utf-8"))
    except Exception:
        return None
    if payload.get("type") != "admin_session":
        return None
    try:
        exp = int(payload.get("exp") or 0)
    except Exception:
        return None
    if exp < int(datetime.utcnow().timestamp()):
        return None
    return payload


def stage62_request_session_payload(request: Request) -> Optional[Dict[str, Any]]:
    return stage62_parse_admin_session_cookie(request.cookies.get(STAGE62_ADMIN_SESSION_COOKIE_NAME) or "")


def stage62_request_has_valid_session(request: Request) -> bool:
    return bool(stage62_request_session_payload(request))


def stage62_set_admin_session_cookie(response: Response, tenant_id: str = TENANT_ID_DEFAULT) -> None:
    session_value = stage62_make_admin_session_cookie(tenant_id=tenant_id)
    if not session_value:
        return
    response.set_cookie(
        key=STAGE62_ADMIN_SESSION_COOKIE_NAME,
        value=session_value,
        httponly=True,
        secure=bool(str(SERVER_BASE_URL or "").lower().startswith("https://")),
        samesite="lax",
        max_age=stage62_session_max_age_seconds(),
    )
    # Remove legacy raw-token cookie if it exists. Header/query auth remains supported.
    response.delete_cookie(key=STAGE61_ADMIN_COOKIE_NAME)


def stage62_clear_admin_session_cookies(response: Response) -> None:
    response.delete_cookie(key=STAGE62_ADMIN_SESSION_COOKIE_NAME)
    response.delete_cookie(key=STAGE61_ADMIN_COOKIE_NAME)


def stage62_safe_local_path(path: str, tenant_id: str = TENANT_ID_DEFAULT) -> str:
    candidate = (path or "").strip()
    if not candidate.startswith("/") or candidate.startswith("//"):
        return f"/tenant/config/ui?tenant_id={urllib.parse.quote((tenant_id or TENANT_ID_DEFAULT).strip() or TENANT_ID_DEFAULT)}"
    # Prevent redirecting to webhook/callback or other public machine endpoints.
    blocked_prefixes = ("/telegram/webhook", "/google/callback")
    if any(candidate.startswith(prefix) for prefix in blocked_prefixes):
        return f"/tenant/config/ui?tenant_id={urllib.parse.quote((tenant_id or TENANT_ID_DEFAULT).strip() or TENANT_ID_DEFAULT)}"
    return candidate



def stage71_owner_auth_enforcement_enabled() -> bool:
    raw = (os.getenv("REPLIQ_OWNER_AUTH_ENFORCEMENT", "true") or "true").strip().lower()
    return raw not in {"0", "false", "no", "off", "disabled", "report_only"}


def stage71_owner_session_max_age_seconds() -> int:
    raw = (os.getenv("REPLIQ_OWNER_SESSION_MAX_AGE_SECONDS", "") or "").strip()
    if raw:
        try:
            return max(300, min(int(raw), 60 * 60 * 24 * 30))
        except Exception:
            pass
    return STAGE71_OWNER_SESSION_MAX_AGE_SECONDS


def stage71_owner_session_secret() -> str:
    # Dedicated owner secret is preferred. Fallback keeps private-demo deploys
    # working, but readiness marks that as not public-SaaS final.
    return (os.getenv("REPLIQ_OWNER_SESSION_SECRET", "") or stage62_session_secret() or "").strip()


def stage71_owner_session_signature(payload_b64: str) -> str:
    secret = stage71_owner_session_secret()
    if not secret:
        return ""
    return hmac.new(secret.encode("utf-8"), payload_b64.encode("ascii"), hashlib.sha256).hexdigest()


def stage71_make_owner_session_cookie(owner_email: str, tenant_id: str, role: str = "owner") -> str:
    now = int(datetime.utcnow().timestamp())
    payload = {
        "v": STAGE71_OWNER_SESSION_VERSION,
        "type": "owner_session",
        "owner_email": stage71_normalize_email(owner_email),
        "tenant_id": (tenant_id or "").strip(),
        "role": (role or "owner").strip() or "owner",
        "iat": now,
        "exp": now + stage71_owner_session_max_age_seconds(),
    }
    raw = json.dumps(payload, ensure_ascii=False, separators=(",", ":")).encode("utf-8")
    payload_b64 = stage62_b64url_encode(raw)
    sig = stage71_owner_session_signature(payload_b64)
    return f"{payload_b64}.{sig}" if sig else ""


def stage71_parse_owner_session_cookie(raw_cookie: str) -> Optional[Dict[str, Any]]:
    raw_cookie = (raw_cookie or "").strip()
    if not raw_cookie or "." not in raw_cookie:
        return None
    payload_b64, sig = raw_cookie.rsplit(".", 1)
    expected = stage71_owner_session_signature(payload_b64)
    if not expected or not hmac.compare_digest(sig, expected):
        return None
    try:
        payload = json.loads(stage62_b64url_decode(payload_b64).decode("utf-8"))
    except Exception:
        return None
    if payload.get("type") != "owner_session":
        return None
    try:
        exp = int(payload.get("exp") or 0)
    except Exception:
        return None
    if exp < int(datetime.utcnow().timestamp()):
        return None
    email = stage71_normalize_email(payload.get("owner_email") or "")
    tenant_id = str(payload.get("tenant_id") or "").strip()
    if not email or not tenant_id:
        return None
    payload["owner_email"] = email
    payload["tenant_id"] = tenant_id
    return payload


def stage71_request_owner_session_payload(request: Request) -> Optional[Dict[str, Any]]:
    return stage71_parse_owner_session_cookie(request.cookies.get(STAGE71_OWNER_SESSION_COOKIE_NAME) or "")


def stage71_set_owner_session_cookie(response: Response, owner_email: str, tenant_id: str, role: str = "owner") -> None:
    session_value = stage71_make_owner_session_cookie(owner_email=owner_email, tenant_id=tenant_id, role=role)
    if not session_value:
        return
    response.set_cookie(
        key=STAGE71_OWNER_SESSION_COOKIE_NAME,
        value=session_value,
        httponly=True,
        secure=bool(str(SERVER_BASE_URL or "").lower().startswith("https://")),
        samesite="lax",
        max_age=stage71_owner_session_max_age_seconds(),
    )


def stage71_clear_owner_session_cookie(response: Response) -> None:
    response.delete_cookie(key=STAGE71_OWNER_SESSION_COOKIE_NAME)


def stage71_path_requires_owner(path: str) -> bool:
    clean = (path or "").rstrip("/") or "/"
    return clean in STAGE71_OWNER_PROTECTED_EXACT_PATHS


def stage71_owner_auth_error(status_code: int, detail: str, tenant_id: str = "") -> JSONResponse:
    tid = (tenant_id or TENANT_ID_DEFAULT).strip() or TENANT_ID_DEFAULT
    return JSONResponse(
        status_code=status_code,
        content={
            "ok": False,
            "stage": "71",
            "error": detail,
            "auth_model": "signed_owner_session_cookie_or_super_admin_session",
            "tenant_id": tid,
            "accepted": {
                "owner_login_page": f"/owner/login?tenant_id={tid}",
                "owner_session_cookie": STAGE71_OWNER_SESSION_COOKIE_NAME,
                "super_admin_bypass": "Stage 62 admin session or Stage 61 admin token",
            },
            "note": "Owner surfaces require a signed owner session bound to the requested tenant. Do not send owner codes or admin tokens in chat logs.",
        },
        headers={"Cache-Control": "no-store"},
    )


def stage71_strict_owner_auth_error(status_code: int, detail: str, tenant_id: str = "") -> JSONResponse:
    tid = (tenant_id or TENANT_ID_DEFAULT).strip() or TENANT_ID_DEFAULT
    return JSONResponse(
        status_code=status_code,
        content={
            "ok": False,
            "stage": "71",
            "error": detail,
            "auth_model": "strict_signed_owner_session_cookie",
            "tenant_id": tid,
            "accepted": {
                "owner_login_page": f"/owner/login?tenant_id={tid}",
                "owner_session_cookie": STAGE71_OWNER_SESSION_COOKIE_NAME,
                "super_admin_bypass": False,
            },
            "note": "This owner surface requires a signed owner session bound to the requested tenant. Admin sessions can use readiness endpoints, not this owner UI/JSON surface.",
        },
        headers={"Cache-Control": "no-store"},
    )


def stage71_owner_request_access(request: Request, path: str = "") -> Dict[str, Any]:
    tenant_id = str(request.query_params.get("tenant_id") or "").strip()
    session = stage71_request_owner_session_payload(request)
    if not session:
        return {"ok": False, "error": "owner_session_required", "tenant_id": tenant_id}
    if not tenant_id:
        tenant_id = str(session.get("tenant_id") or "").strip()
    email = stage71_normalize_email(session.get("owner_email") or "")
    if not email or not tenant_id:
        return {"ok": False, "error": "owner_session_missing_email_or_tenant", "tenant_id": tenant_id}
    if not stage71_owner_has_tenant_access(email, tenant_id):
        return {"ok": False, "error": "owner_tenant_access_denied", "tenant_id": tenant_id, "owner_email": email}
    return {"ok": True, "tenant_id": tenant_id, "owner_email": email, "role": session.get("role") or "owner"}


# -------------------------
# STAGE 74: CSRF / BROWSER WRITE HARDENING FOUNDATION
# -------------------------
STAGE74_CSRF_HEADER_NAME = "x-repliq-csrf-token"
STAGE74_CSRF_ALT_HEADER_NAMES = ("x-csrf-token", "x-xsrf-token")
STAGE74_CSRF_TOKEN_TTL_SECONDS = 60 * 60 * 4
STAGE74_CSRF_TOKEN_VERSION = 1

# Browser writes that are authenticated by admin/owner cookies must pass a same-origin
# browser metadata check or a signed CSRF token. External channel webhooks and public
# OAuth callbacks are intentionally excluded from this browser-CSRF layer.
STAGE74_ADMIN_BROWSER_WRITE_PATHS = {
    "/owner/accounts/bootstrap",
    "/owner/magic-link/bootstrap",
    "/tenant/owner/bind",
    "/google/select_calendar",
    "/tenant/billing/update",
    "/tenant/business-memory/update",
    "/business-memory/update",
    "/telegram/setup/update",
    "/telegram/setup/set-webhook",
    "/telegram/set-webhook",
    "/onboarding/finish",
    "/onboarding/create_tenant",
    "/tenant/create",
    "/tenant/change_plan",
    "/tenant/service-catalog/update",
    "/service-catalog/update",
    "/tenant/config/update",
    "/dev_chat",
    "/dev_reset",
    "/dev_understand",
    "/dev_focus_test",
    "/dev/dialogue-simulate",
}
STAGE74_OWNER_BROWSER_WRITE_PATHS = {
    "/owner/demo/preview",
    "/owner/client-preview/message",
    "/owner/business-memory/update",
    "/owner/faq/update",
    "/owner/services/update",
    "/owner/service-catalog/update",
    "/owner/business-profile/update",
    "/owner/availability/update",
    "/owner/logout",
}
STAGE74_PUBLIC_BROWSER_WRITE_PATHS = {
    "/public/signup",
}
STAGE74_EXTERNAL_WEBHOOK_WRITE_PATHS = {
    "/voice/incoming",
    "/voice/language",
    "/voice/intent",
    "/sms/incoming",
    "/whatsapp/incoming",
    "/telegram/webhook",
}


def stage74_normalize_path(path: str) -> str:
    return (path or "").rstrip("/") or "/"


def stage74_csrf_enforcement_enabled() -> bool:
    raw = (os.getenv("REPLIQ_CSRF_ENFORCEMENT", "true") or "true").strip().lower()
    return raw not in {"0", "false", "no", "off", "disabled", "report_only"}


def stage74_csrf_secret() -> str:
    return (
        os.getenv("REPLIQ_CSRF_SECRET", "")
        or stage71_owner_session_secret()
        or stage62_session_secret()
        or stage61_admin_token_value()
        or "stage74-dev-fallback"
    ).strip()


def stage74_csrf_secret_source() -> str:
    if (os.getenv("REPLIQ_CSRF_SECRET", "") or "").strip():
        return "REPLIQ_CSRF_SECRET"
    if stage71_owner_session_secret():
        return "owner_session_secret_fallback"
    if stage62_session_secret():
        return "admin_session_secret_fallback"
    if stage61_admin_token_value():
        return "admin_token_fallback"
    return "dev_fallback"


def stage61_request_non_cookie_token(request: Request) -> str:
    for key in STAGE61_ADMIN_HEADER_KEYS:
        value = (request.headers.get(key) or "").strip()
        if value:
            return value
    auth = (request.headers.get("authorization") or "").strip()
    if auth.lower().startswith("bearer "):
        return auth[7:].strip()
    return stage61_query_token(request)


def stage74_make_csrf_token(scope: str = "admin", tenant_id: str = "") -> str:
    now = int(datetime.utcnow().timestamp())
    payload = {
        "v": STAGE74_CSRF_TOKEN_VERSION,
        "type": "csrf_token",
        "scope": str(scope or "admin").strip().lower() or "admin",
        "tenant_id": str(tenant_id or "*").strip() or "*",
        "iat": now,
        "exp": now + STAGE74_CSRF_TOKEN_TTL_SECONDS,
        "nonce": secrets.token_urlsafe(16),
    }
    raw = json.dumps(payload, ensure_ascii=False, separators=(",", ":")).encode("utf-8")
    payload_b64 = stage62_b64url_encode(raw)
    sig = hmac.new(stage74_csrf_secret().encode("utf-8"), payload_b64.encode("ascii"), hashlib.sha256).hexdigest()
    return f"{payload_b64}.{sig}"


def stage74_parse_csrf_token(raw_token: str) -> Optional[Dict[str, Any]]:
    raw_token = (raw_token or "").strip()
    if not raw_token or "." not in raw_token:
        return None
    payload_b64, sig = raw_token.rsplit(".", 1)
    expected = hmac.new(stage74_csrf_secret().encode("utf-8"), payload_b64.encode("ascii"), hashlib.sha256).hexdigest()
    try:
        if not hmac.compare_digest(sig, expected):
            return None
        payload = json.loads(stage62_b64url_decode(payload_b64).decode("utf-8"))
    except Exception:
        return None
    if payload.get("type") != "csrf_token":
        return None
    try:
        exp = int(payload.get("exp") or 0)
    except Exception:
        return None
    if exp < int(datetime.utcnow().timestamp()):
        return None
    return payload


def stage74_request_csrf_token(request: Request) -> str:
    value = (request.headers.get(STAGE74_CSRF_HEADER_NAME) or "").strip()
    if value:
        return value
    for key in STAGE74_CSRF_ALT_HEADER_NAMES:
        value = (request.headers.get(key) or "").strip()
        if value:
            return value
    return ""


def stage74_csrf_token_valid_for_request(request: Request, scope: str, tenant_id: str = "") -> bool:
    payload = stage74_parse_csrf_token(stage74_request_csrf_token(request))
    if not payload:
        return False
    expected_scope = str(scope or "admin").strip().lower() or "admin"
    token_scope = str(payload.get("scope") or "").strip().lower()
    if token_scope != expected_scope:
        return False
    expected_tenant = str(tenant_id or "").strip()
    token_tenant = str(payload.get("tenant_id") or "*").strip() or "*"
    if expected_tenant and token_tenant not in {"*", expected_tenant}:
        return False
    return True


def stage74_origin_host_candidates(request: Request) -> List[str]:
    values: List[str] = []
    try:
        host = str(request.url.netloc or "").lower()
        if host:
            values.append(host)
    except Exception:
        pass
    forwarded_host = str(request.headers.get("x-forwarded-host") or "").split(",")[0].strip().lower()
    if forwarded_host:
        values.append(forwarded_host)
    configured = (SERVER_BASE_URL or "").strip()
    if configured:
        try:
            parsed = urllib.parse.urlparse(configured)
            if parsed.netloc:
                values.append(parsed.netloc.lower())
        except Exception:
            pass
    return list(dict.fromkeys([v for v in values if v]))


def stage74_same_origin_browser_metadata_ok(request: Request) -> bool:
    sec_fetch_site = (request.headers.get("sec-fetch-site") or "").strip().lower()
    if sec_fetch_site:
        return sec_fetch_site in {"same-origin", "none"}

    allowed_hosts = set(stage74_origin_host_candidates(request))
    origin = (request.headers.get("origin") or "").strip()
    if origin:
        try:
            parsed = urllib.parse.urlparse(origin)
            return (parsed.netloc or "").lower() in allowed_hosts
        except Exception:
            return False

    referer = (request.headers.get("referer") or "").strip()
    if referer:
        try:
            parsed = urllib.parse.urlparse(referer)
            return (parsed.netloc or "").lower() in allowed_hosts
        except Exception:
            return False

    # Non-browser API clients and Render health/internal checks usually do not send
    # Fetch Metadata / Origin / Referer. They are not CSRF-able without browser cookies.
    return True


def stage74_browser_write_protection_ok(request: Request, scope: str, tenant_id: str = "") -> bool:
    if stage74_csrf_token_valid_for_request(request, scope=scope, tenant_id=tenant_id):
        return True
    return stage74_same_origin_browser_metadata_ok(request)


def stage74_csrf_error(scope: str, tenant_id: str = "", reason: str = "csrf_browser_write_check_failed") -> JSONResponse:
    return JSONResponse(
        status_code=403,
        content={
            "ok": False,
            "stage": "74",
            "error": reason,
            "scope": scope,
            "tenant_id": tenant_id or None,
            "csrf_header": STAGE74_CSRF_HEADER_NAME,
            "accepted": [
                "same-origin browser request metadata",
                "signed CSRF token in X-Repliq-CSRF-Token",
                "explicit admin token header/bearer/query for admin API automation",
            ],
            "note": "Stage 74 blocks cross-site browser writes that rely on signed admin/owner session cookies. It does not expose session secrets or raw tokens.",
        },
        headers={"Cache-Control": "no-store"},
    )


def stage74_csrf_write_hardening_readiness_payload(tenant_id: str = TENANT_ID_DEFAULT) -> Dict[str, Any]:
    tid = (tenant_id or "").strip() or TENANT_ID_DEFAULT
    required_paths = [
        "/csrf/readiness",
        "/security/csrf/readiness",
        "/browser-write/readiness",
        "/browser-write-hardening/readiness",
    ]
    missing_protection = [path for path in required_paths if path not in STAGE61_PROTECTED_EXACT_PATHS]
    admin_write_paths_missing_admin_protection = [path for path in sorted(STAGE74_ADMIN_BROWSER_WRITE_PATHS) if path not in STAGE61_PROTECTED_EXACT_PATHS]
    owner_write_paths_missing_owner_protection = [path for path in sorted(STAGE74_OWNER_BROWSER_WRITE_PATHS) if path not in STAGE71_OWNER_PROTECTED_EXACT_PATHS and path not in {"/owner/logout"}]
    blocking: List[str] = []
    warnings: List[str] = []
    if missing_protection:
        blocking.append("stage74_readiness_paths_not_admin_protected")
    if admin_write_paths_missing_admin_protection:
        blocking.append("admin_browser_write_paths_not_admin_protected")
    if owner_write_paths_missing_owner_protection:
        blocking.append("owner_browser_write_paths_not_owner_protected")
    if not stage74_csrf_enforcement_enabled():
        blocking.append("csrf_enforcement_disabled")
    secret_source = stage74_csrf_secret_source()
    if secret_source != "REPLIQ_CSRF_SECRET":
        warnings.append(f"csrf_secret_uses_{secret_source}")

    ready = bool(not blocking and stage74_csrf_secret())
    return {
        "ok": True,
        "stage": "74",
        "purpose": "CSRF / Browser Write Hardening Foundation",
        "tenant_id": tid,
        "status": "ready" if ready else "blocked",
        "csrf_browser_write_hardening_ready": bool(ready),
        "csrf_enforcement_enabled": bool(stage74_csrf_enforcement_enabled()),
        "protection_model": {
            "signed_csrf_token_supported": True,
            "same_origin_fetch_metadata_enforced": True,
            "origin_referer_fallback_check_enabled": True,
            "admin_api_token_bypass_for_automation": True,
            "cookie_authenticated_browser_writes_hardened": True,
            "public_signup_cross_site_browser_post_blocked": True,
        },
        "csrf_token": {
            "header": STAGE74_CSRF_HEADER_NAME,
            "ttl_seconds": STAGE74_CSRF_TOKEN_TTL_SECONDS,
            "secret_configured_explicitly": bool(secret_source == "REPLIQ_CSRF_SECRET"),
            "secret_source": secret_source,
            "token_value_exposed_in_readiness": False,
            "raw_secret_exposed": False,
        },
        "write_routes": {
            "admin_browser_write_paths": sorted(STAGE74_ADMIN_BROWSER_WRITE_PATHS),
            "owner_browser_write_paths": sorted(STAGE74_OWNER_BROWSER_WRITE_PATHS),
            "public_browser_write_paths": sorted(STAGE74_PUBLIC_BROWSER_WRITE_PATHS),
            "external_webhook_write_paths_excluded": sorted(STAGE74_EXTERNAL_WEBHOOK_WRITE_PATHS),
        },
        "security": {
            "admin_write_routes_protected_by_admin_auth": not bool(admin_write_paths_missing_admin_protection),
            "owner_write_routes_have_owner_boundary_or_logout_exception": not bool(owner_write_paths_missing_owner_protection),
            "raw_admin_token_exposed": False,
            "raw_owner_session_secret_exposed": False,
            "raw_csrf_secret_exposed": False,
            "csrf_token_value_exposed_in_readiness": False,
        },
        "public_saas_ready": False,
        "public_saas_ready_reason": "false_until_client_owner_vs_super_admin_separation_and_final_launch_gate_are_done",
        "blocking": list(dict.fromkeys([str(x) for x in blocking if str(x)])),
        "warnings": list(dict.fromkeys([str(x) for x in warnings if str(x)])),
        "links": {
            "csrf_token_admin": f"/csrf/token?scope=admin&tenant_id={tid}",
            "readiness": f"/csrf/readiness?tenant_id={tid}",
            "public_saas_audit": f"/public-saas/readiness?tenant_id={tid}",
            "control_center": f"/control-center/ui?tenant_id={tid}",
        },
        "note": "Stage 74 hardens authenticated browser writes and public signup cross-site POSTs. It does not change receptionist dialogue, booking, slot generation, Google Calendar event runtime, Telegram webhook runtime, billing semantics, or QA evaluator behavior.",
    }


# -------------------------
# STAGE 75: ABUSE PROTECTION / RATE LIMITS HARDENING FOUNDATION
# -------------------------
STAGE75_ABUSE_EVENTS_TABLE = "abuse_events"
STAGE75_READINESS_PATHS = (
    "/abuse/readiness",
    "/security/abuse/readiness",
    "/rate-limits/readiness",
    "/abuse-protection/readiness",
)
STAGE75_MONITORED_BUCKETS = (
    "admin_login",
    "owner_login",
    "public_signup",
    "public_csrf_token",
)


def stage75_abuse_protection_enabled() -> bool:
    raw = (os.getenv("REPLIQ_ABUSE_PROTECTION_ENABLED", "true") or "true").strip().lower()
    return raw not in {"0", "false", "no", "off", "disabled", "report_only"}


def stage75_fail_open_enabled() -> bool:
    raw = (os.getenv("REPLIQ_ABUSE_PROTECTION_FAIL_OPEN", "true") or "true").strip().lower()
    return raw not in {"0", "false", "no", "off", "disabled"}


def stage75_int_env(name: str, default: int, low: int, high: int) -> int:
    raw = (os.getenv(name, str(default)) or str(default)).strip()
    try:
        return max(low, min(int(raw), high))
    except Exception:
        return int(default)


def stage75_admin_login_ip_hourly_limit() -> int:
    return stage75_int_env("REPLIQ_ADMIN_LOGIN_IP_HOURLY_LIMIT", 30, 3, 500)


def stage75_owner_login_ip_hourly_limit() -> int:
    return stage75_int_env("REPLIQ_OWNER_LOGIN_IP_HOURLY_LIMIT", 30, 3, 500)


def stage75_owner_login_subject_hourly_limit() -> int:
    return stage75_int_env("REPLIQ_OWNER_LOGIN_SUBJECT_HOURLY_LIMIT", 10, 3, 100)


def stage75_public_signup_ip_hourly_limit() -> int:
    return stage75_int_env("REPLIQ_PUBLIC_SIGNUP_ABUSE_IP_HOURLY_LIMIT", 10, 1, 100)


def stage75_public_signup_subject_daily_limit() -> int:
    return stage75_int_env("REPLIQ_PUBLIC_SIGNUP_ABUSE_SUBJECT_DAILY_LIMIT", 5, 1, 50)


def stage75_public_csrf_token_ip_hourly_limit() -> int:
    return stage75_int_env("REPLIQ_PUBLIC_CSRF_TOKEN_IP_HOURLY_LIMIT", 120, 10, 2000)


def stage75_abuse_secret() -> str:
    return (
        os.getenv("REPLIQ_ABUSE_PROTECTION_SECRET", "")
        or os.getenv("REPLIQ_PUBLIC_SIGNUP_SECRET", "")
        or stage71_owner_session_secret()
        or stage62_session_secret()
        or stage61_admin_token_value()
        or "stage75-dev-fallback"
    ).strip()


def stage75_abuse_secret_source() -> str:
    if (os.getenv("REPLIQ_ABUSE_PROTECTION_SECRET", "") or "").strip():
        return "REPLIQ_ABUSE_PROTECTION_SECRET"
    if (os.getenv("REPLIQ_PUBLIC_SIGNUP_SECRET", "") or "").strip():
        return "public_signup_secret_fallback"
    if stage71_owner_session_secret():
        return "owner_session_secret_fallback"
    if stage62_session_secret():
        return "admin_session_secret_fallback"
    if stage61_admin_token_value():
        return "admin_token_fallback"
    return "dev_fallback"


def stage75_hash_value(value: str) -> str:
    raw = str(value or "").strip() or "unknown"
    return hmac.new(stage75_abuse_secret().encode("utf-8"), raw.encode("utf-8"), hashlib.sha256).hexdigest()


def stage75_client_ip_hash(request: Optional[Request]) -> str:
    raw_ip = ""
    try:
        forwarded = str((request.headers.get("x-forwarded-for") if request else "") or "").split(",")[0].strip()
        raw_ip = forwarded or str((request.client.host if request and request.client else "") or "").strip()
    except Exception:
        raw_ip = ""
    return stage75_hash_value(raw_ip or "unknown")


def stage75_user_agent(request: Optional[Request]) -> str:
    try:
        return str((request.headers.get("user-agent") if request else "") or "")[:240]
    except Exception:
        return ""


def stage75_ensure_abuse_events_table() -> None:
    with engine.begin() as conn:
        conn.execute(text("""
            CREATE TABLE IF NOT EXISTS abuse_events (
                id TEXT PRIMARY KEY,
                bucket TEXT NOT NULL,
                path TEXT,
                tenant_id TEXT,
                subject_hash TEXT,
                ip_hash TEXT,
                status TEXT NOT NULL DEFAULT 'received',
                reason TEXT,
                user_agent TEXT,
                created_at TIMESTAMPTZ DEFAULT NOW()
            )
        """))
        conn.execute(text("CREATE INDEX IF NOT EXISTS idx_abuse_events_bucket_ip_created_at ON abuse_events(bucket, ip_hash, created_at)"))
        conn.execute(text("CREATE INDEX IF NOT EXISTS idx_abuse_events_bucket_subject_created_at ON abuse_events(bucket, subject_hash, created_at)"))
        conn.execute(text("CREATE INDEX IF NOT EXISTS idx_abuse_events_tenant_created_at ON abuse_events(tenant_id, created_at)"))


def stage75_abuse_table_exists() -> bool:
    try:
        with engine.connect() as conn:
            row = conn.execute(text("""
                SELECT EXISTS (
                    SELECT 1 FROM information_schema.tables
                    WHERE table_schema='public' AND table_name=:table_name
                )
            """), {"table_name": STAGE75_ABUSE_EVENTS_TABLE}).fetchone()
        return bool(row and row[0])
    except Exception:
        return False


def stage75_record_abuse_event(request: Optional[Request], bucket: str, subject: str = "", tenant_id: str = "", status: str = "received", reason: str = "") -> None:
    if not stage75_abuse_protection_enabled():
        return
    try:
        stage75_ensure_abuse_events_table()
        path = ""
        try:
            path = str((request.url.path if request else "") or "")[:160]
        except Exception:
            path = ""
        with engine.begin() as conn:
            conn.execute(text("""
                INSERT INTO abuse_events (id, bucket, path, tenant_id, subject_hash, ip_hash, status, reason, user_agent, created_at)
                VALUES (:id, :bucket, :path, :tenant_id, :subject_hash, :ip_hash, :status, :reason, :user_agent, NOW())
            """), {
                "id": "abus_" + uuid.uuid4().hex,
                "bucket": str(bucket or "unknown")[:80],
                "path": path or None,
                "tenant_id": str(tenant_id or "").strip()[:80] or None,
                "subject_hash": stage75_hash_value(subject) if str(subject or "").strip() else None,
                "ip_hash": stage75_client_ip_hash(request),
                "status": str(status or "received")[:40],
                "reason": str(reason or "")[:160] or None,
                "user_agent": stage75_user_agent(request) or None,
            })
    except Exception as e:
        log.error("stage75_record_abuse_event_failed bucket=%s err=%s", bucket, e)


def stage75_count_events(bucket: str, ip_hash: str = "", subject_hash: str = "", window_seconds: int = 3600) -> int:
    cutoff = datetime.utcnow() - timedelta(seconds=max(1, int(window_seconds or 3600)))
    where = ["bucket=:bucket", "created_at > :cutoff"]
    params: Dict[str, Any] = {"bucket": bucket, "cutoff": cutoff}
    if ip_hash:
        where.append("ip_hash=:ip_hash")
        params["ip_hash"] = ip_hash
    if subject_hash:
        where.append("subject_hash=:subject_hash")
        params["subject_hash"] = subject_hash
    with engine.connect() as conn:
        return int(conn.execute(text("SELECT COUNT(*) FROM abuse_events WHERE " + " AND ".join(where)), params).scalar() or 0)


def stage75_rate_limit_check(request: Optional[Request], bucket: str, subject: str = "", tenant_id: str = "", ip_limit: int = 30, ip_window_seconds: int = 3600, subject_limit: int = 0, subject_window_seconds: int = 3600) -> Dict[str, Any]:
    if not stage75_abuse_protection_enabled():
        return {"ok": True, "stage": "75", "reason": "abuse_protection_disabled", "enforced": False}
    try:
        stage75_ensure_abuse_events_table()
        ip_hash = stage75_client_ip_hash(request)
        if int(ip_limit or 0) > 0:
            ip_count = stage75_count_events(bucket=bucket, ip_hash=ip_hash, window_seconds=ip_window_seconds)
            if ip_count >= int(ip_limit):
                return {"ok": False, "stage": "75", "reason": f"{bucket}_ip_rate_limit", "bucket": bucket, "limit": int(ip_limit), "window_seconds": int(ip_window_seconds), "retry_after_seconds": int(ip_window_seconds), "ip_hash_exposed": False, "subject_hash_exposed": False}
        subject_clean = str(subject or "").strip()
        if subject_clean and int(subject_limit or 0) > 0:
            subject_count = stage75_count_events(bucket=bucket, subject_hash=stage75_hash_value(subject_clean), window_seconds=subject_window_seconds)
            if subject_count >= int(subject_limit):
                return {"ok": False, "stage": "75", "reason": f"{bucket}_subject_rate_limit", "bucket": bucket, "limit": int(subject_limit), "window_seconds": int(subject_window_seconds), "retry_after_seconds": int(subject_window_seconds), "ip_hash_exposed": False, "subject_hash_exposed": False}
        return {"ok": True, "stage": "75", "reason": "ok", "bucket": bucket, "enforced": True, "ip_hash_exposed": False, "subject_hash_exposed": False}
    except Exception as e:
        log.error("stage75_rate_limit_check_failed bucket=%s err=%s", bucket, e)
        if stage75_fail_open_enabled():
            return {"ok": True, "stage": "75", "reason": "rate_limit_storage_unavailable_fail_open", "error": e.__class__.__name__, "enforced": False, "ip_hash_exposed": False, "subject_hash_exposed": False}
        return {"ok": False, "stage": "75", "reason": "rate_limit_storage_unavailable", "error": e.__class__.__name__, "ip_hash_exposed": False, "subject_hash_exposed": False}


def stage75_admin_login_gate(request: Optional[Request], tenant_id: str = "") -> Dict[str, Any]:
    return stage75_rate_limit_check(request, bucket="admin_login", subject=str(tenant_id or "").strip() or "admin", tenant_id=tenant_id, ip_limit=stage75_admin_login_ip_hourly_limit(), ip_window_seconds=3600, subject_limit=0)


def stage75_owner_login_gate(request: Optional[Request], tenant_id: str = "", owner_email: str = "") -> Dict[str, Any]:
    subject = f"{str(tenant_id or '').strip()}:{stage71_normalize_email(owner_email)}"
    return stage75_rate_limit_check(request, bucket="owner_login", subject=subject, tenant_id=tenant_id, ip_limit=stage75_owner_login_ip_hourly_limit(), ip_window_seconds=3600, subject_limit=stage75_owner_login_subject_hourly_limit(), subject_window_seconds=3600)


def stage75_public_signup_gate(request: Optional[Request], owner_email: str = "", tenant_id: str = "") -> Dict[str, Any]:
    subject = f"{str(tenant_id or '').strip()}:{stage71_normalize_email(owner_email)}"
    by_ip = stage75_rate_limit_check(request, bucket="public_signup", subject="", tenant_id=tenant_id, ip_limit=stage75_public_signup_ip_hourly_limit(), ip_window_seconds=3600, subject_limit=0)
    if not by_ip.get("ok"):
        return by_ip
    return stage75_rate_limit_check(request, bucket="public_signup", subject=subject, tenant_id=tenant_id, ip_limit=0, subject_limit=stage75_public_signup_subject_daily_limit(), subject_window_seconds=60 * 60 * 24)


def stage75_public_csrf_token_gate(request: Optional[Request], tenant_id: str = "") -> Dict[str, Any]:
    return stage75_rate_limit_check(request, bucket="public_csrf_token", subject=str(tenant_id or "public").strip() or "public", tenant_id=tenant_id, ip_limit=stage75_public_csrf_token_ip_hourly_limit(), ip_window_seconds=3600, subject_limit=0)


def stage75_abuse_error(result: Dict[str, Any], tenant_id: str = "") -> JSONResponse:
    result = dict(result or {})
    retry_after = int(result.get("retry_after_seconds") or 3600)
    return JSONResponse(status_code=429, content={"ok": False, "stage": "75", "error": str(result.get("reason") or "rate_limited"), "bucket": result.get("bucket"), "tenant_id": tenant_id or None, "retry_after_seconds": retry_after, "ip_hash_exposed": False, "subject_hash_exposed": False, "raw_admin_token_exposed": False, "raw_owner_login_code_exposed": False, "note": "Stage 75 abuse protection blocks repeated login/signup/token attempts without exposing raw IPs, subject hashes, admin tokens, or owner codes."}, headers={"Cache-Control": "no-store", "Retry-After": str(retry_after)})


def stage75_recent_counts(hours: int = 24) -> Dict[str, int]:
    hours = max(1, min(int(hours or 24), 168))
    cutoff = datetime.utcnow() - timedelta(hours=hours)
    counts: Dict[str, int] = {bucket: 0 for bucket in STAGE75_MONITORED_BUCKETS}
    try:
        if not stage75_abuse_table_exists():
            return counts
        with engine.connect() as conn:
            rows = conn.execute(text("""
                SELECT bucket, COUNT(*) FROM abuse_events
                WHERE created_at > :cutoff
                GROUP BY bucket
            """), {"cutoff": cutoff}).fetchall()
        for row in rows:
            bucket = str(row[0] or "")
            if bucket:
                counts[bucket] = int(row[1] or 0)
    except Exception as e:
        log.error("stage75_recent_counts_failed err=%s", e)
    return counts


def stage75_abuse_rate_limits_readiness_payload(tenant_id: str = TENANT_ID_DEFAULT, hours: int = 24) -> Dict[str, Any]:
    tid = (tenant_id or TENANT_ID_DEFAULT).strip() or TENANT_ID_DEFAULT
    hours = max(1, min(int(hours or 24), 168))
    blocking: List[str] = []
    warnings: List[str] = []
    try:
        stage75_ensure_abuse_events_table()
    except Exception:
        blocking.append("abuse_events_table_unavailable")
    table_exists = stage75_abuse_table_exists()
    if not table_exists:
        blocking.append("abuse_events_table_missing")
    if not stage75_abuse_protection_enabled():
        blocking.append("abuse_protection_disabled")
    secret_source = stage75_abuse_secret_source()
    if secret_source != "REPLIQ_ABUSE_PROTECTION_SECRET":
        warnings.append(f"abuse_secret_uses_{secret_source}")
    if stage75_fail_open_enabled():
        warnings.append("abuse_protection_fail_open_enabled_foundation_mode")
    missing_protection = [path for path in STAGE75_READINESS_PATHS if path not in STAGE61_PROTECTED_EXACT_PATHS]
    if missing_protection:
        blocking.append("stage75_readiness_paths_not_admin_protected")
    if not stage72_public_signup_table_exists():
        warnings.append("stage72_public_signup_specific_rate_limit_table_missing")
    counts = stage75_recent_counts(hours=hours)
    ready = bool(not blocking)
    return {
        "ok": True,
        "stage": "75",
        "purpose": "Abuse Protection / Rate Limits Hardening Foundation",
        "tenant_id": tid,
        "status": "ready" if ready and not warnings else "attention" if ready else "blocked",
        "abuse_rate_limits_ready": bool(ready),
        "public_abuse_protection_foundation_ready": bool(ready),
        "enforcement_enabled": bool(stage75_abuse_protection_enabled()),
        "fail_open_foundation_mode": bool(stage75_fail_open_enabled()),
        "storage": {"abuse_events_table": bool(table_exists), "public_signup_events_table": bool(stage72_public_signup_table_exists()), "raw_ip_exposed": False, "subject_hash_exposed": False},
        "policies": {
            "admin_login": {"ip_hourly_limit": stage75_admin_login_ip_hourly_limit(), "records_success_and_failure": True},
            "owner_login": {"ip_hourly_limit": stage75_owner_login_ip_hourly_limit(), "subject_hourly_limit": stage75_owner_login_subject_hourly_limit(), "records_success_and_failure": True},
            "public_signup": {"ip_hourly_limit": stage75_public_signup_ip_hourly_limit(), "subject_daily_limit": stage75_public_signup_subject_daily_limit(), "stage72_specific_limits_still_active": True},
            "public_csrf_token": {"ip_hourly_limit": stage75_public_csrf_token_ip_hourly_limit()},
        },
        "monitored_routes": {
            "admin_login": ["POST /admin/login"],
            "owner_login": ["POST /owner/login", "GET /owner/magic-login?token=...", "POST /owner/magic-login"],
            "public_signup": ["POST /public/signup"],
            "csrf_token_public_scope": ["GET /csrf/token?scope=public"],
            "external_webhooks_not_rate_limited_in_stage75": sorted(STAGE74_EXTERNAL_WEBHOOK_WRITE_PATHS),
        },
        "recent_event_counts": {"window_hours": hours, "by_bucket": counts},
        "security": {"raw_admin_token_exposed": False, "raw_owner_login_code_exposed": False, "raw_ip_exposed": False, "subject_hash_exposed": False, "readiness_routes_admin_protected": not bool(missing_protection)},
        "public_saas_ready": False,
        "public_saas_ready_reason": "false_until_client_owner_vs_super_admin_separation_and_final_launch_gate_are_done",
        "blocking": list(dict.fromkeys([str(x) for x in blocking if str(x)])),
        "warnings": list(dict.fromkeys([str(x) for x in warnings if str(x)])),
        "links": {"readiness": f"/abuse/readiness?tenant_id={tid}", "rate_limits_readiness": f"/rate-limits/readiness?tenant_id={tid}", "public_saas_audit": f"/public-saas/readiness?tenant_id={tid}", "control_center": f"/control-center/ui?tenant_id={tid}"},
        "note": "Stage 75 adds a central abuse ledger and rate-limit gates for admin login, owner login, public signup, and public CSRF token issuance. It does not change receptionist dialogue, booking, slots, calendar event runtime, Telegram webhook runtime, billing semantics, or QA evaluator behavior.",
    }


# -------------------------
# STAGE 76: EMAIL VERIFICATION / MAGIC LINK AUTH FOUNDATION
# -------------------------
STAGE76_MAGIC_LINKS_TABLE = "owner_magic_links"
STAGE76_READINESS_PATHS = {
    "/email/readiness",
    "/email-verification/readiness",
    "/magic-link/readiness",
    "/owner/magic-link/readiness",
}
STAGE76_ADMIN_WRITE_PATHS = {
    "/owner/magic-link/bootstrap",
}
STAGE76_PUBLIC_MAGIC_LOGIN_PATHS = {
    "/owner/magic-login",
}
STAGE76_MAGIC_LINK_TOKEN_PREFIX = "ml_"
STAGE76_MAGIC_LINK_TOKEN_VERSION = 1


def stage76_magic_link_auth_enabled() -> bool:
    raw = (os.getenv("REPLIQ_MAGIC_LINK_AUTH_ENABLED", "true") or "true").strip().lower()
    return raw not in {"0", "false", "no", "off", "disabled"}


def stage76_magic_link_ttl_seconds() -> int:
    raw = (os.getenv("REPLIQ_MAGIC_LINK_TTL_SECONDS", "") or "").strip()
    if raw:
        try:
            return max(300, min(int(raw), 60 * 60 * 24))
        except Exception:
            pass
    return 60 * 30


def stage76_magic_link_secret() -> str:
    return (
        os.getenv("REPLIQ_MAGIC_LINK_SECRET", "")
        or stage71_owner_session_secret()
        or stage62_session_secret()
        or stage61_admin_token_value()
        or "stage76-dev-fallback"
    ).strip()


def stage76_magic_link_secret_source() -> str:
    if (os.getenv("REPLIQ_MAGIC_LINK_SECRET", "") or "").strip():
        return "REPLIQ_MAGIC_LINK_SECRET"
    if stage71_owner_session_secret():
        return "owner_session_secret_fallback"
    if stage62_session_secret():
        return "admin_session_secret_fallback"
    if stage61_admin_token_value():
        return "admin_token_fallback"
    return "dev_fallback"


def stage76_email_delivery_provider_configured() -> bool:
    return bool(
        (os.getenv("REPLIQ_EMAIL_DELIVERY_PROVIDER", "") or "").strip()
        or (os.getenv("SMTP_HOST", "") or "").strip()
        or (os.getenv("RESEND_API_KEY", "") or "").strip()
        or (os.getenv("SENDGRID_API_KEY", "") or "").strip()
    )


def stage76_table_exists(table_name: str) -> bool:
    try:
        with engine.connect() as conn:
            row = conn.execute(text("""
                SELECT EXISTS (
                    SELECT 1 FROM information_schema.tables
                    WHERE table_schema='public' AND table_name=:table_name
                )
            """), {"table_name": table_name}).fetchone()
        return bool(row and row[0])
    except Exception:
        return False


def stage76_ensure_magic_link_tables() -> None:
    stage71_ensure_owner_tables()
    with engine.begin() as conn:
        conn.execute(text("ALTER TABLE owner_accounts ADD COLUMN IF NOT EXISTS email_verified_at TIMESTAMPTZ"))
        conn.execute(text("""
            CREATE TABLE IF NOT EXISTS owner_magic_links (
                id TEXT PRIMARY KEY,
                owner_email TEXT NOT NULL,
                tenant_id TEXT NOT NULL,
                purpose TEXT NOT NULL DEFAULT 'login',
                token_hash TEXT UNIQUE NOT NULL,
                status TEXT NOT NULL DEFAULT 'active',
                expires_at TIMESTAMPTZ NOT NULL,
                created_at TIMESTAMPTZ DEFAULT NOW(),
                consumed_at TIMESTAMPTZ,
                requested_by TEXT
            )
        """))
        conn.execute(text("CREATE INDEX IF NOT EXISTS idx_owner_magic_links_email_tenant_status ON owner_magic_links(owner_email, tenant_id, status)"))
        conn.execute(text("CREATE INDEX IF NOT EXISTS idx_owner_magic_links_token_hash ON owner_magic_links(token_hash)"))
        conn.execute(text("CREATE INDEX IF NOT EXISTS idx_owner_magic_links_expires_at ON owner_magic_links(expires_at)"))


def stage76_make_magic_link_token() -> str:
    return STAGE76_MAGIC_LINK_TOKEN_PREFIX + secrets.token_urlsafe(32)


def stage76_hash_magic_link_token(token: str) -> str:
    raw = str(token or "").strip()
    if not raw:
        return ""
    msg = f"stage76-magic-link-token:{raw}".encode("utf-8")
    return hmac.new(stage76_magic_link_secret().encode("utf-8"), msg, hashlib.sha256).hexdigest()


def stage76_base_url() -> str:
    return (SERVER_BASE_URL or "").rstrip("/")


def stage76_magic_login_url(token: str, tenant_id: str = "", next_path: str = "") -> str:
    tid = str(tenant_id or "").strip()
    base = stage76_base_url()
    path = "/owner/magic-login?token=" + urllib.parse.quote(str(token or ""), safe="")
    if tid:
        path += "&tenant_id=" + urllib.parse.quote(tid, safe="")
    if next_path:
        path += "&next=" + urllib.parse.quote(stage62_safe_local_path(next_path, tid or TENANT_ID_DEFAULT), safe="")
    return base + path if base else path


def stage76_create_magic_link(tenant_id: str, owner_email: str, purpose: str = "login", requested_by: str = "system", next_path: str = "") -> Dict[str, Any]:
    if not stage76_magic_link_auth_enabled():
        raise ValueError("magic_link_auth_disabled")
    tid = str(tenant_id or "").strip()
    email = stage71_normalize_email(owner_email)
    purpose_clean = str(purpose or "login").strip().lower() or "login"
    if not tid:
        raise ValueError("tenant_id_required")
    if not get_existing_tenant(tid).get("_id"):
        raise ValueError("tenant_not_found")
    if not stage71_valid_email(email):
        raise ValueError("owner_email_invalid")
    if not stage71_owner_has_tenant_access(email, tid):
        raise ValueError("owner_tenant_access_denied")
    stage76_ensure_magic_link_tables()
    token = stage76_make_magic_link_token()
    token_hash = stage76_hash_magic_link_token(token)
    expires_at = datetime.utcnow() + timedelta(seconds=stage76_magic_link_ttl_seconds())
    with engine.begin() as conn:
        conn.execute(text("""
            UPDATE owner_magic_links
            SET status='revoked'
            WHERE owner_email=:email AND tenant_id=:tenant_id AND purpose=:purpose AND status='active'
        """), {"email": email, "tenant_id": tid, "purpose": purpose_clean})
        conn.execute(text("""
            INSERT INTO owner_magic_links (id, owner_email, tenant_id, purpose, token_hash, status, expires_at, created_at, requested_by)
            VALUES (:id, :email, :tenant_id, :purpose, :token_hash, 'active', :expires_at, NOW(), :requested_by)
        """), {
            "id": "magic_" + uuid.uuid4().hex,
            "email": email,
            "tenant_id": tid,
            "purpose": purpose_clean,
            "token_hash": token_hash,
            "expires_at": expires_at,
            "requested_by": str(requested_by or "system")[:80],
        })
    link_url = stage76_magic_login_url(token, tid, next_path or f"/owner/dashboard/ui?tenant_id={tid}")
    return {
        "ok": True,
        "stage": "76",
        "tenant_id": tid,
        "owner_email": email,
        "purpose": purpose_clean,
        "magic_link_url": link_url,
        "magic_link_token": token,
        "magic_link_token_returned_once": True,
        "token_expires_at": expires_at.isoformat() + "Z",
        "ttl_seconds": stage76_magic_link_ttl_seconds(),
        "email_delivery_provider_configured": bool(stage76_email_delivery_provider_configured()),
        "email_delivery_attempted": False,
        "token_hash_exposed": False,
        "raw_token_stored": False,
        "note": "Stage 76 foundation returns the magic link once. Real outbound email delivery is intentionally not attempted unless a later email-provider stage adds it.",
    }


def stage76_get_magic_link_row(token: str) -> Dict[str, Any]:
    token_hash = stage76_hash_magic_link_token(token)
    if not token_hash:
        return {}
    stage76_ensure_magic_link_tables()
    with engine.connect() as conn:
        row = conn.execute(text("""
            SELECT id, owner_email, tenant_id, purpose, status, expires_at, created_at, consumed_at, (expires_at < NOW()) AS expired
            FROM owner_magic_links
            WHERE token_hash=:token_hash
            ORDER BY created_at DESC
            LIMIT 1
        """), {"token_hash": token_hash}).fetchone()
    if not row:
        return {}
    def iso(v):
        return v.isoformat() if hasattr(v, "isoformat") and v else v
    return {
        "id": row[0],
        "owner_email": stage71_normalize_email(row[1]),
        "tenant_id": str(row[2] or "").strip(),
        "purpose": str(row[3] or "login"),
        "status": str(row[4] or ""),
        "expires_at": iso(row[5]),
        "created_at": iso(row[6]),
        "consumed_at": iso(row[7]),
        "expired": bool(row[8]),
        "token_hash_exposed": False,
    }


def stage76_consume_magic_link_token(token: str) -> Tuple[bool, str, Dict[str, Any]]:
    raw = str(token or "").strip()
    if not raw:
        return False, "magic_token_required", {}
    if not stage76_magic_link_auth_enabled():
        return False, "magic_link_auth_disabled", {}
    try:
        row = stage76_get_magic_link_row(raw)
    except Exception as e:
        log.error("stage76_magic_link_lookup_failed err=%s", e)
        return False, "magic_link_storage_unavailable", {}
    if not row:
        return False, "magic_token_not_found", {}
    if row.get("status") != "active":
        return False, "magic_token_not_active", row
    if row.get("expired"):
        return False, "magic_token_expired", row
    email = stage71_normalize_email(row.get("owner_email"))
    tid = str(row.get("tenant_id") or "").strip()
    if not stage71_owner_has_tenant_access(email, tid):
        return False, "owner_tenant_access_denied", row
    with engine.begin() as conn:
        updated = conn.execute(text("""
            UPDATE owner_magic_links
            SET status='consumed', consumed_at=NOW()
            WHERE id=:id AND status='active' AND expires_at >= NOW()
        """), {"id": row.get("id")})
        if int(getattr(updated, "rowcount", 0) or 0) < 1:
            return False, "magic_token_already_used_or_expired", row
        conn.execute(text("""
            UPDATE owner_accounts
            SET email_verified_at=COALESCE(email_verified_at, NOW()), last_login_at=NOW()
            WHERE email=:email
        """), {"email": email})
    row["status"] = "consumed"
    row["email_verified"] = True
    return True, "ok", row


def stage76_owner_email_verification_status(owner_email: str = "") -> Dict[str, Any]:
    email = stage71_normalize_email(owner_email)
    if not email:
        return {"owner_email": None, "email_verified": False, "email_verified_at": None, "email_verified_at_exposed": False}
    try:
        stage76_ensure_magic_link_tables()
        with engine.connect() as conn:
            row = conn.execute(text("SELECT email_verified_at FROM owner_accounts WHERE email=:email LIMIT 1"), {"email": email}).fetchone()
        value = row[0] if row else None
        return {
            "owner_email": email,
            "email_verified": bool(value),
            "email_verified_at": value.isoformat() if hasattr(value, "isoformat") and value else value,
            "email_verified_at_exposed": bool(value),
        }
    except Exception as e:
        log.error("stage76_owner_email_verification_status_failed email=%s err=%s", email, e)
        return {"owner_email": email, "email_verified": False, "email_verified_at": None, "error": e.__class__.__name__, "email_verified_at_exposed": False}


def stage76_recent_magic_link_counts(hours: int = 24) -> Dict[str, int]:
    hours = max(1, min(int(hours or 24), 168))
    counts = {"active": 0, "consumed": 0, "revoked": 0, "expired": 0}
    try:
        if not stage76_table_exists(STAGE76_MAGIC_LINKS_TABLE):
            return counts
        cutoff = datetime.utcnow() - timedelta(hours=hours)
        with engine.connect() as conn:
            rows = conn.execute(text("""
                SELECT status, COUNT(*)
                FROM owner_magic_links
                WHERE created_at > :cutoff
                GROUP BY status
            """), {"cutoff": cutoff}).fetchall()
        for row in rows:
            status = str(row[0] or "unknown")
            counts[status] = int(row[1] or 0)
    except Exception as e:
        log.error("stage76_recent_magic_link_counts_failed err=%s", e)
    return counts


def stage76_email_magic_link_readiness_payload(tenant_id: str = TENANT_ID_DEFAULT, hours: int = 24) -> Dict[str, Any]:
    tid = (tenant_id or TENANT_ID_DEFAULT).strip() or TENANT_ID_DEFAULT
    hours = max(1, min(int(hours or 24), 168))
    blocking: List[str] = []
    warnings: List[str] = []
    try:
        stage76_ensure_magic_link_tables()
    except Exception as e:
        blocking.append(f"magic_link_storage_unavailable:{e.__class__.__name__}")
    magic_table = stage76_table_exists(STAGE76_MAGIC_LINKS_TABLE)
    owner_table = stage71_owner_table_exists("owner_accounts")
    access_table = stage71_owner_table_exists("owner_tenant_access")
    if not magic_table:
        blocking.append("owner_magic_links_table_missing")
    if not owner_table:
        blocking.append("owner_accounts_table_missing")
    if not access_table:
        blocking.append("owner_tenant_access_table_missing")
    if not stage76_magic_link_auth_enabled():
        blocking.append("magic_link_auth_disabled")
    if not stage76_magic_link_secret():
        blocking.append("magic_link_secret_not_configured")
    secret_source = stage76_magic_link_secret_source()
    if secret_source != "REPLIQ_MAGIC_LINK_SECRET":
        warnings.append(f"magic_link_secret_uses_{secret_source}")
    if not stage76_email_delivery_provider_configured():
        warnings.append("email_delivery_provider_not_configured_foundation_returns_link_once")
    missing_protection = [path for path in STAGE76_READINESS_PATHS | STAGE76_ADMIN_WRITE_PATHS if path not in STAGE61_PROTECTED_EXACT_PATHS]
    if missing_protection:
        blocking.append("stage76_admin_readiness_or_bootstrap_paths_not_protected")
    public_magic_paths_wrongly_admin_protected = [path for path in STAGE76_PUBLIC_MAGIC_LOGIN_PATHS if path in STAGE61_PROTECTED_EXACT_PATHS or path in STAGE71_OWNER_PROTECTED_EXACT_PATHS]
    if public_magic_paths_wrongly_admin_protected:
        blocking.append("public_magic_login_path_wrongly_protected")
    csrf_write_missing = [path for path in STAGE76_ADMIN_WRITE_PATHS if path not in STAGE74_ADMIN_BROWSER_WRITE_PATHS]
    if csrf_write_missing:
        blocking.append("stage76_admin_magic_link_write_not_csrf_hardened")
    counts = stage76_recent_magic_link_counts(hours=hours)
    ready = bool(not blocking)
    return {
        "ok": True,
        "stage": "76",
        "purpose": "Email Verification / Magic Link Auth Foundation",
        "tenant_id": tid,
        "status": "ready" if ready and not warnings else "attention" if ready else "blocked",
        "email_verification_magic_link_foundation_ready": bool(ready),
        "magic_link_auth_ready": bool(ready),
        "owner_magic_login_ready": bool(ready),
        "email_verification_storage_ready": bool(magic_table and owner_table),
        "email_delivery_provider_configured": bool(stage76_email_delivery_provider_configured()),
        "email_delivery_attempted": False,
        "ttl_seconds": stage76_magic_link_ttl_seconds(),
        "storage": {"owner_magic_links_table": bool(magic_table), "owner_accounts_table": bool(owner_table), "owner_tenant_access_table": bool(access_table), "raw_magic_token_stored": False, "token_hash_exposed": False},
        "protected_paths": {"readiness_admin_protected": sorted(STAGE76_READINESS_PATHS), "admin_magic_link_bootstrap_protected": sorted(STAGE76_ADMIN_WRITE_PATHS), "public_magic_login_paths": sorted(STAGE76_PUBLIC_MAGIC_LOGIN_PATHS), "missing_protection": missing_protection},
        "auth_model": {"magic_link_token_prefix": STAGE76_MAGIC_LINK_TOKEN_PREFIX, "one_time_token": True, "sets_owner_session_cookie": STAGE71_OWNER_SESSION_COOKIE_NAME, "marks_email_verified_at": True, "legacy_login_code_still_supported": True, "token_hash_exposed": False, "raw_token_stored": False},
        "recent_magic_link_counts": {"window_hours": hours, "by_status": counts},
        "public_saas_ready": False,
        "public_saas_ready_reason": "false_until_client_owner_vs_super_admin_separation_and_final_launch_gate_are_done",
        "blocking": list(dict.fromkeys([str(x) for x in blocking if str(x)])),
        "warnings": list(dict.fromkeys([str(x) for x in warnings if str(x)])),
        "links": {"readiness": f"/email/readiness?tenant_id={tid}", "magic_link_readiness": f"/magic-link/readiness?tenant_id={tid}", "owner_magic_login": f"/owner/magic-login?tenant_id={tid}", "owner_magic_link_bootstrap": "/owner/magic-link/bootstrap", "public_saas_audit": f"/public-saas/readiness?tenant_id={tid}", "control_center": f"/control-center/ui?tenant_id={tid}"},
        "note": "Stage 76 adds one-time owner magic-link auth and email_verified_at foundation. It does not send real emails yet unless a later email provider stage is added, and it does not change receptionist booking/runtime behavior.",
    }


