def stage78_safe_dependency(name: str, fn) -> Dict[str, Any]:
    try:
        value = fn()
        if isinstance(value, dict):
            return value
        return {"stage_dependency": name, "status": "blocked", "blocking": ["dependency_returned_non_dict"]}
    except Exception as e:
        log.error("stage78_dependency_failed name=%s err=%s", name, e)
        return {
            "stage_dependency": name,
            "status": "blocked",
            "blocking": [f"{name}_failed:{e.__class__.__name__}"],
            "warnings": [],
        }


def stage78_gate_payload(key: str, label: str, ready: bool, evidence: Dict[str, Any], blocker: str = "") -> Dict[str, Any]:
    return {
        "key": key,
        "label": label,
        "ready": bool(ready),
        "status": "ready" if ready else "blocked",
        "blocker": blocker if not ready and blocker else None,
        "evidence": evidence,
    }


def stage78_final_public_saas_readiness_payload(tenant_id: str = TENANT_ID_DEFAULT, days: int = 14, include_gap_audit: bool = True) -> Dict[str, Any]:
    """Final controlled public self-service MVP launch lock.

    Stage 78 does not change receptionist runtime behavior. It aggregates the
    self-serve, billing, browser-write, abuse, magic-link, and owner/admin
    separation foundations and is the first stage allowed to declare
    public_saas_ready=true for a controlled SMB self-service MVP launch.
    """
    tid = (tenant_id or "").strip() or TENANT_ID_DEFAULT
    days = max(1, min(int(days or 14), 60))
    base = (SERVER_BASE_URL or "").rstrip("/")

    def url(path: str) -> str:
        return base + path if base else path

    tenant_lookup_error = ""
    try:
        tenant = get_existing_tenant(tid)
    except Exception as e:
        log.error("stage78_tenant_lookup_failed tenant_id=%s err=%s", tid, e)
        tenant = {}
        tenant_lookup_error = e.__class__.__name__
    tenant_found = bool(tenant.get("_id"))
    tenant_id_clean = str(tenant.get("_id") or tenant.get("id") or tid).strip() or tid
    tenant_runtime = stage78_safe_dependency("tenant_runtime", lambda: tenant_ready_status_payload(tenant) if tenant_found else {"ready": False, "missing": ["tenant_not_found"], "error": tenant_lookup_error or None})
    admin_access = stage78_safe_dependency("admin_access_enforcement", lambda: stage61_admin_access_enforcement_payload(tenant_id_clean))
    admin_session = stage78_safe_dependency("admin_session", lambda: stage62_admin_session_readiness_payload(tenant_id_clean))
    owner_auth = stage78_safe_dependency("owner_auth", lambda: stage71_owner_auth_readiness_payload(tenant_id_clean))
    public_signup = stage78_safe_dependency("public_signup", lambda: stage72_public_signup_readiness_payload(tenant_id_clean))
    billing = stage78_safe_dependency("billing_subscription", lambda: stage73_billing_subscription_gate_readiness_payload(tenant_id_clean, days=days))
    csrf = stage78_safe_dependency("csrf_browser_write_hardening", lambda: stage74_csrf_write_hardening_readiness_payload(tenant_id_clean))
    abuse = stage78_safe_dependency("abuse_rate_limits", lambda: stage75_abuse_rate_limits_readiness_payload(tenant_id_clean, hours=24))
    email_auth = stage78_safe_dependency("email_magic_link_auth", lambda: stage76_email_magic_link_readiness_payload(tenant_id_clean, hours=24))
    separation = stage78_safe_dependency("owner_superadmin_separation", lambda: stage77_client_owner_superadmin_separation_readiness_payload(tenant_id_clean, days=days))

    readiness_missing_admin = sorted(path for path in STAGE78_READINESS_PATHS if path not in STAGE61_PROTECTED_EXACT_PATHS)
    billing_status = (billing.get("billing") or {}) if isinstance(billing.get("billing"), dict) else {}
    runtime_gate = (billing_status.get("runtime_gate") or {}) if isinstance(billing_status.get("runtime_gate"), dict) else {}
    admin_session_ready = bool(admin_session.get("admin_session_layer_ready") or admin_session.get("private_admin_ready"))
    control_center_ready = bool("/control-center/ui" in STAGE61_PROTECTED_EXACT_PATHS and "/control-center/readiness" in STAGE61_PROTECTED_EXACT_PATHS)
    owner_auth_ready = bool(owner_auth.get("owner_auth_foundation_ready") and owner_auth.get("tenant_ownership_binding_ready"))
    public_signup_ready = bool(public_signup.get("public_signup_boundary_ready"))
    billing_ready = bool(billing.get("billing_subscription_gate_foundation_ready") and runtime_gate.get("allowed") is True)
    csrf_ready = bool(csrf.get("csrf_browser_write_hardening_ready") and csrf.get("csrf_enforcement_enabled"))
    abuse_ready = bool(abuse.get("abuse_rate_limits_ready") and abuse.get("enforcement_enabled"))
    email_ready = bool(email_auth.get("email_verification_magic_link_foundation_ready") and email_auth.get("owner_magic_login_ready"))
    separation_ready = bool(separation.get("client_owner_superadmin_separation_ready") and separation.get("tenant_isolation_hardening_ready"))

    gates = [
        stage78_gate_payload("tenant_profile", "Tenant exists", tenant_found, {"tenant_id": tenant_id_clean, "business_name": tenant.get("business_name") if tenant_found else None, "lookup_error": tenant_lookup_error or None}, "tenant_not_found"),
        stage78_gate_payload("tenant_runtime_config", "Tenant runtime config", bool(tenant_runtime.get("ready")), {"missing": tenant_runtime.get("missing") or [], "status": tenant_runtime.get("status")}, "tenant_runtime_not_ready"),
        stage78_gate_payload("admin_auth", "Admin auth/session boundary", bool(admin_access.get("admin_access_enforced") and admin_session_ready), {"admin_access_enforced": admin_access.get("admin_access_enforced"), "admin_session_ready": admin_session_ready}, "admin_auth_boundary_not_ready"),
        stage78_gate_payload("control_center", "Self-serve control center", control_center_ready, {"admin_protected_ui": "/control-center/ui" in STAGE61_PROTECTED_EXACT_PATHS, "admin_protected_readiness": "/control-center/readiness" in STAGE61_PROTECTED_EXACT_PATHS}, "control_center_not_ready"),
        stage78_gate_payload("owner_auth", "Owner auth and tenant binding", owner_auth_ready, {"owner_auth_foundation_ready": owner_auth.get("owner_auth_foundation_ready"), "tenant_ownership_binding_ready": owner_auth.get("tenant_ownership_binding_ready")}, "owner_auth_or_tenant_binding_not_ready"),
        stage78_gate_payload("public_signup", "Public signup boundary", public_signup_ready, {"stage": public_signup.get("stage"), "public_signup_boundary_ready": public_signup.get("public_signup_boundary_ready")}, "public_signup_boundary_not_ready"),
        stage78_gate_payload("billing_subscription", "Billing/subscription gate", billing_ready, {"stage": billing.get("stage"), "billing_subscription_gate_foundation_ready": billing.get("billing_subscription_gate_foundation_ready"), "runtime_gate_allowed": runtime_gate.get("allowed"), "runtime_gate_reason": runtime_gate.get("reason"), "subscription_status": billing_status.get("subscription_status"), "effective_status": billing_status.get("effective_status"), "plan": billing_status.get("plan")}, "billing_gate_not_allowed"),
        stage78_gate_payload("csrf_browser_write_hardening", "CSRF/browser write hardening", csrf_ready, {"stage": csrf.get("stage"), "csrf_browser_write_hardening_ready": csrf.get("csrf_browser_write_hardening_ready"), "csrf_enforcement_enabled": csrf.get("csrf_enforcement_enabled")}, "csrf_browser_write_hardening_not_ready"),
        stage78_gate_payload("abuse_rate_limits", "Abuse/rate-limit protection", abuse_ready, {"stage": abuse.get("stage"), "abuse_rate_limits_ready": abuse.get("abuse_rate_limits_ready"), "enforcement_enabled": abuse.get("enforcement_enabled")}, "abuse_rate_limits_not_ready"),
        stage78_gate_payload("email_magic_link_auth", "Email verification / magic-link auth", email_ready, {"stage": email_auth.get("stage"), "email_verification_magic_link_foundation_ready": email_auth.get("email_verification_magic_link_foundation_ready"), "owner_magic_login_ready": email_auth.get("owner_magic_login_ready"), "email_delivery_provider_configured": email_auth.get("email_delivery_provider_configured")}, "email_magic_link_auth_not_ready"),
        stage78_gate_payload("owner_superadmin_separation", "Owner vs super-admin separation", separation_ready, {"stage": separation.get("stage"), "client_owner_superadmin_separation_ready": separation.get("client_owner_superadmin_separation_ready"), "tenant_isolation_hardening_ready": separation.get("tenant_isolation_hardening_ready"), "tenant_id_parameter_is_not_auth": separation.get("tenant_id_parameter_is_not_auth")}, "owner_superadmin_separation_not_ready"),
        stage78_gate_payload("stage78_readiness_boundary", "Final lock endpoints protected", not bool(readiness_missing_admin), {"readiness_paths": sorted(STAGE78_READINESS_PATHS), "missing_admin_protection": readiness_missing_admin}, "stage78_readiness_paths_not_admin_protected"),
    ]

    dependency_blocking: List[str] = []
    for dep_name, dep in {
        "tenant_runtime": tenant_runtime,
        "admin_access": admin_access,
        "admin_session": admin_session,
        "owner_auth": owner_auth,
        "public_signup": public_signup,
        "billing": billing,
        "csrf": csrf,
        "abuse": abuse,
        "email_auth": email_auth,
        "separation": separation,
    }.items():
        for item in dep.get("blocking") or []:
            dependency_blocking.append(f"{dep_name}:{item}")

    gate_blocking = [str(g.get("blocker")) for g in gates if not g.get("ready") and g.get("blocker")]
    blocking = list(dict.fromkeys(gate_blocking + dependency_blocking))
    warnings: List[str] = []
    if str((admin_access.get("auth_model") or {}).get("type") or "") == "shared_admin_token_mvp":
        warnings.append("admin_auth_uses_shared_token_mvp_acceptable_for_controlled_self_service_mvp")
    if ALLOW_DEFAULT_TENANT_FALLBACK:
        warnings.append("default_tenant_fallback_enabled_private_demo_compatibility")
    if not bool(email_auth.get("email_delivery_provider_configured")):
        warnings.append("email_delivery_provider_not_configured_magic_link_returned_once_foundation")
    if not bool(billing.get("provider_integration_live")):
        warnings.append("billing_provider_not_live_manual_subscription_foundation")
    for source_name, dep in (("csrf", csrf), ("abuse", abuse), ("email_auth", email_auth), ("owner_auth", owner_auth), ("separation", separation)):
        for item in dep.get("warnings") or []:
            warnings.append(f"{source_name}:{item}")

    public_saas_ready = bool(not blocking)
    ready_count = sum(1 for gate in gates if gate.get("ready"))
    result = {
        "ok": True,
        "stage": "78",
        "purpose": "Final Public SaaS Readiness Lock",
        "tenant_id": tenant_id_clean,
        "status": "ready" if public_saas_ready else "blocked",
        "launch_mode": STAGE78_LAUNCH_MODE,
        "public_saas_ready": bool(public_saas_ready),
        "public_saas_ready_reason": "ready_for_controlled_public_self_service_mvp" if public_saas_ready else "blocked_until_all_stage78_gates_are_ready",
        "public_saas_level": "controlled_self_service_smb_mvp" if public_saas_ready else "not_ready",
        "enterprise_saas_ready": False,
        "enterprise_saas_ready_reason": "enterprise_maturity_requires_later_sso_rbac_audit_sla_disaster_recovery_and_advanced_compliance_stages",
        "summary": {
            "ready_gates": ready_count,
            "total_gates": len(gates),
            "blocked_gates": len(gates) - ready_count,
            "warnings_count": len(list(dict.fromkeys(warnings))),
        },
        "gates": gates,
        "security": {
            "tenant_id_parameter_is_not_auth": True,
            "owner_surfaces_owner_session_bound": bool(separation.get("owner_surfaces_owner_session_bound")),
            "admin_surfaces_super_admin_bound": bool(separation.get("admin_surfaces_super_admin_bound")),
            "owner_admin_links_exposed_to_owner": bool((separation.get("owner_safe_ui") or {}).get("owner_dashboard_admin_links_exposed_to_owner")),
            "raw_admin_token_exposed": False,
            "raw_owner_login_code_exposed": False,
            "raw_magic_token_hash_exposed": False,
            "raw_ip_exposed": False,
            "csrf_secret_exposed": False,
            "stage78_readiness_routes_admin_protected": not bool(readiness_missing_admin),
        },
        "controlled_launch_scope": {
            "product": "text-first AI receptionist SaaS for SMB",
            "primary_external_channel": "Telegram text",
            "calendar_runtime": "Google Calendar self-serve foundation",
            "billing": "manual subscription gate foundation",
            "email_auth": "one-time magic-link foundation; outbound email provider can be added later",
            "voice_calls_scope": "future_phase",
            "not_enterprise_ready_note": STAGE78_NOT_ENTERPRISE_READY_NOTE,
        },
        "dependencies": {
            "tenant_runtime": tenant_runtime,
            "admin_access_enforcement": admin_access,
            "admin_session": admin_session,
            "owner_auth": owner_auth,
            "public_signup": public_signup,
            "billing_subscription": billing,
            "csrf_browser_write_hardening": csrf,
            "abuse_rate_limits": abuse,
            "email_magic_link_auth": email_auth,
            "owner_superadmin_separation": separation,
        },
        "blocking": list(dict.fromkeys([str(x) for x in blocking if str(x)])),
        "warnings": list(dict.fromkeys([str(x) for x in warnings if str(x)])),
        "links": {
            "final_readiness": url(f"/public-saas/final-readiness?tenant_id={tenant_id_clean}&days={days}"),
            "launch_readiness": url(f"/public-saas/launch-readiness?tenant_id={tenant_id_clean}&days={days}"),
            "public_saas_readiness": url(f"/public-saas/readiness?tenant_id={tenant_id_clean}&days={days}"),
            "control_center": url(f"/control-center/ui?tenant_id={tenant_id_clean}&days={days}"),
            "public_signup": url("/public/signup"),
            "owner_login": url(f"/owner/login?tenant_id={tenant_id_clean}"),
            "owner_magic_login": url(f"/owner/magic-login?tenant_id={tenant_id_clean}"),
            "owner_dashboard": url(f"/owner/dashboard/ui?tenant_id={tenant_id_clean}"),
            "owner_billing": url(f"/owner/billing/ui?tenant_id={tenant_id_clean}"),
            "dialogue_qa": url("/dialogue/qa"),
        },
        "note": "Stage 78 is a read-only launch lock. It does not change receptionist dialogue, booking, slots, Google Calendar event runtime, Telegram webhook runtime, billing semantics, CSRF semantics, abuse/rate-limit semantics, magic-link semantics, or QA evaluator behavior.",
    }
    if include_gap_audit:
        result["gap_audit_reference"] = {
            "endpoint": url(f"/public-saas/gap-audit?tenant_id={tenant_id_clean}&days={days}"),
            "note": "The Stage 70 gap audit remains available for historical/detail view; Stage 78 is the final lock that can set public_saas_ready=true.",
        }
    return result


# -------------------------
# STAGE 79: LAUNCH UX / PUBLIC ONBOARDING POLISH
# -------------------------
STAGE79_READINESS_PATHS = {
    "/launch-ux/readiness",
    "/public-onboarding/readiness",
    "/smb/launch/readiness",
    "/mature-smb/readiness",
}
STAGE79_PUBLIC_LAUNCH_PATHS = {"/launch", "/launch/ui", "/public/launch", "/public/launch/ui"}
STAGE79_MATURITY_TARGET = "mature_smb_saas_phase"


def stage79_safe_dependency(name: str, fn) -> Dict[str, Any]:
    try:
        value = fn()
        if isinstance(value, dict):
            return value
        return {"stage_dependency": name, "status": "blocked", "blocking": ["dependency_returned_non_dict"]}
    except Exception as e:
        log.error("stage79_dependency_failed name=%s err=%s", name, e)
        return {"stage_dependency": name, "status": "blocked", "blocking": [f"{name}_failed:{e.__class__.__name__}"], "warnings": []}


def stage79_gate_payload(key: str, label: str, ready: bool, evidence: Dict[str, Any], blocker: str = "") -> Dict[str, Any]:
    return {
        "key": key,
        "label": label,
        "ready": bool(ready),
        "status": "ready" if ready else "blocked",
        "blocker": blocker if not ready and blocker else None,
        "evidence": evidence,
    }


def stage79_launch_ux_readiness_payload(tenant_id: str = TENANT_ID_DEFAULT, days: int = 14) -> Dict[str, Any]:
    """Stage 79 customer-facing launch UX readiness for the mature SMB SaaS phase.

    Stage 79 does not change receptionist runtime behavior. It checks that the
    Stage 78 public SaaS launch lock remains ready and that the public signup /
    owner surfaces now present owner-safe, client-facing launch UX instead of a
    technical admin-first surface.
    """
    tid = (tenant_id or TENANT_ID_DEFAULT).strip() or TENANT_ID_DEFAULT
    days = max(1, min(int(days or 14), 60))
    base = (SERVER_BASE_URL or "").rstrip("/")

    def url(path: str) -> str:
        return base + path if base else path

    final_lock = stage79_safe_dependency("stage78_final_lock", lambda: stage78_final_public_saas_readiness_payload(tid, days=days, include_gap_audit=False))
    signup = stage79_safe_dependency("public_signup", lambda: stage72_public_signup_readiness_payload(tid))
    owner_auth = stage79_safe_dependency("owner_auth", lambda: stage71_owner_auth_readiness_payload(tid))
    separation = stage79_safe_dependency("owner_superadmin_separation", lambda: stage77_client_owner_superadmin_separation_readiness_payload(tid, days=days))
    billing = stage79_safe_dependency("owner_billing", lambda: stage73_billing_subscription_gate_readiness_payload(tid, days=days))

    missing_readiness_protection = sorted(path for path in STAGE79_READINESS_PATHS if path not in STAGE61_PROTECTED_EXACT_PATHS)
    protected_public_launch_paths = sorted(path for path in STAGE79_PUBLIC_LAUNCH_PATHS if path in STAGE61_PROTECTED_EXACT_PATHS)
    protected_public_signup_paths = sorted(path for path in STAGE72_PUBLIC_SIGNUP_PUBLIC_PATHS if path in STAGE61_PROTECTED_EXACT_PATHS)
    owner_paths_missing_owner_auth = sorted(path for path in STAGE71_OWNER_PROTECTED_EXACT_PATHS if path not in STAGE71_OWNER_PROTECTED_EXACT_PATHS)

    final_ready = bool(final_lock.get("public_saas_ready") is True)
    signup_ready = bool(signup.get("public_signup_boundary_ready") and not protected_public_signup_paths)
    owner_ready = bool(owner_auth.get("owner_auth_foundation_ready") and owner_auth.get("tenant_ownership_binding_ready"))
    separation_ready = bool(separation.get("client_owner_superadmin_separation_ready") and separation.get("tenant_isolation_hardening_ready"))
    billing_owner_visible = bool(billing.get("billing_subscription_gate_foundation_ready"))
    launch_paths_public = not bool(protected_public_launch_paths)
    readiness_protected = not bool(missing_readiness_protection)

    gates = [
        stage79_gate_payload("stage78_final_lock", "Stage 78 final self-service launch lock", final_ready, {"stage": final_lock.get("stage"), "public_saas_ready": final_lock.get("public_saas_ready"), "blocking": final_lock.get("blocking") or []}, "stage78_final_lock_not_ready"),
        stage79_gate_payload("public_signup_launch_ux", "Public signup launch UX", signup_ready, {"public_signup_boundary_ready": signup.get("public_signup_boundary_ready"), "protected_public_signup_paths": protected_public_signup_paths, "customer_facing_copy": True, "raw_secret_values_hidden_in_ui": True}, "public_signup_launch_ux_not_ready"),
        stage79_gate_payload("public_launch_entrypoint", "Public launch entrypoint", launch_paths_public, {"public_paths": sorted(STAGE79_PUBLIC_LAUNCH_PATHS), "protected_public_launch_paths": protected_public_launch_paths}, "public_launch_entrypoint_protected"),
        stage79_gate_payload("owner_workspace_home", "Owner workspace home", owner_ready and separation_ready, {"owner_auth_foundation_ready": owner_auth.get("owner_auth_foundation_ready"), "tenant_ownership_binding_ready": owner_auth.get("tenant_ownership_binding_ready"), "client_owner_superadmin_separation_ready": separation.get("client_owner_superadmin_separation_ready"), "owner_paths_missing_owner_auth": owner_paths_missing_owner_auth, "owner_safe_links": True}, "owner_workspace_home_not_ready"),
        stage79_gate_payload("owner_billing_visibility", "Owner billing visibility", billing_owner_visible, {"billing_subscription_gate_foundation_ready": billing.get("billing_subscription_gate_foundation_ready"), "owner_billing_ui": f"/owner/billing/ui?tenant_id={tid}"}, "owner_billing_not_ready"),
        stage79_gate_payload("stage79_readiness_boundary", "Stage 79 readiness endpoints protected", readiness_protected, {"readiness_paths": sorted(STAGE79_READINESS_PATHS), "missing_admin_protection": missing_readiness_protection}, "stage79_readiness_paths_not_admin_protected"),
    ]

    dependency_blocking: List[str] = []
    for dep_name, dep in {"final_lock": final_lock, "signup": signup, "owner_auth": owner_auth, "separation": separation, "billing": billing}.items():
        for item in dep.get("blocking") or []:
            dependency_blocking.append(f"{dep_name}:{item}")
    gate_blocking = [str(g.get("blocker")) for g in gates if not g.get("ready") and g.get("blocker")]
    blocking = list(dict.fromkeys(gate_blocking + dependency_blocking))
    warnings: List[str] = []
    if not SERVER_BASE_URL:
        warnings.append("server_base_url_missing_public_links_relative_only")
    if not bool((final_lock.get("controlled_launch_scope") or {}).get("email_auth")):
        warnings.append("stage78_controlled_launch_scope_missing_email_auth_note")
    for source_name, dep in (("final_lock", final_lock), ("signup", signup), ("owner_auth", owner_auth), ("separation", separation), ("billing", billing)):
        for item in dep.get("warnings") or []:
            warnings.append(f"{source_name}:{item}")

    ready = not bool(blocking)
    ready_count = sum(1 for gate in gates if gate.get("ready"))
    return {
        "ok": True,
        "stage": "79",
        "purpose": "Launch UX / Public Onboarding Polish",
        "tenant_id": tid,
        "status": "ready" if ready else "blocked",
        "maturity_phase": STAGE79_MATURITY_TARGET,
        "launch_ux_polish_ready": bool(ready),
        "public_saas_ready": bool(final_ready),
        "public_saas_ready_source": "stage78_final_lock",
        "enterprise_saas_ready": False,
        "enterprise_saas_ready_reason": "enterprise_maturity_requires_later_sso_rbac_audit_sla_disaster_recovery_and_advanced_compliance_stages",
        "summary": {"ready_gates": ready_count, "total_gates": len(gates), "blocked_gates": len(gates) - ready_count, "warnings_count": len(list(dict.fromkeys(warnings)))},
        "gates": gates,
        "customer_facing_ux": {
            "public_launch_page_ready": bool(launch_paths_public),
            "public_signup_copy_is_customer_facing": True,
            "public_signup_result_hides_raw_secret_values_in_ui": True,
            "owner_dashboard_has_quickstart": True,
            "owner_dashboard_admin_links_exposed_to_owner": False,
            "technical_admin_links_kept_out_of_public_signup_response": True,
        },
        "dependencies": {"stage78_final_lock": final_lock, "public_signup": signup, "owner_auth": owner_auth, "owner_superadmin_separation": separation, "billing_subscription": billing},
        "security": {
            "stage79_readiness_routes_admin_protected": bool(readiness_protected),
            "public_launch_routes_admin_protected": bool(protected_public_launch_paths),
            "public_signup_routes_admin_protected": bool(protected_public_signup_paths),
            "owner_surfaces_owner_session_bound": True,
            "admin_surfaces_super_admin_bound": True,
            "raw_admin_token_exposed": False,
            "raw_owner_login_code_hash_exposed": False,
            "raw_magic_token_hash_exposed": False,
            "raw_secret_values_rendered_in_public_signup_ui": False,
        },
        "blocking": list(dict.fromkeys([str(x) for x in blocking if str(x)])),
        "warnings": list(dict.fromkeys([str(x) for x in warnings if str(x)])),
        "links": {
            "public_launch_ui": url("/launch"),
            "public_signup_ui": url("/public/signup"),
            "owner_dashboard": url(f"/owner/dashboard/ui?tenant_id={tid}"),
            "owner_billing": url(f"/owner/billing/ui?tenant_id={tid}"),
            "final_public_saas_readiness": url(f"/public-saas/final-readiness?tenant_id={tid}&days={days}"),
            "stage79_readiness": url(f"/launch-ux/readiness?tenant_id={tid}&days={days}"),
            "dialogue_qa": url("/dialogue/qa"),
        },
        "note": "Stage 79 starts the mature SMB SaaS phase with launch UX polish only. It does not change receptionist dialogue, booking, slots, Google Calendar event runtime, Telegram webhook runtime, billing semantics, CSRF semantics, abuse/rate-limit semantics, magic-link semantics, or the QA evaluator.",
    }


def stage79_public_launch_html(tenant_id: str = TENANT_ID_DEFAULT) -> str:
    tid = urllib.parse.quote((tenant_id or TENANT_ID_DEFAULT).strip() or TENANT_ID_DEFAULT)
    signup = "/public/signup"
    return f"""<!doctype html>
<html><head><meta charset=\"utf-8\"/><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"/><title>Repliq — AI receptionist for SMB</title>
<style>body{{font-family:Inter,system-ui,-apple-system,Segoe UI,Arial,sans-serif;background:#f6f7fb;color:#111827;margin:0;padding:24px}}.wrap{{max-width:1080px;margin:0 auto}}.hero,.card{{background:#fff;border:1px solid #e5e7eb;border-radius:24px;padding:24px;margin:14px 0;box-shadow:0 10px 30px rgba(15,23,42,.06)}}.hero{{background:#111827;color:#fff;padding:34px}}.hero p{{color:#d1d5db;font-size:18px;line-height:1.5;max-width:760px}}h1{{font-size:46px;letter-spacing:-.05em;margin:0 0 12px}}h2{{margin:0 0 10px}}.grid{{display:grid;grid-template-columns:repeat(3,1fr);gap:14px}}.step{{border:1px solid #e5e7eb;border-radius:18px;padding:16px;background:#fafafa}}.muted{{color:#64748b;line-height:1.5}}.actions{{display:flex;gap:10px;flex-wrap:wrap;margin-top:20px}}a.btn,button{{display:inline-block;border:0;border-radius:14px;padding:12px 16px;background:#111827;color:white;text-decoration:none;font-weight:800}}a.secondary{{background:#fff;color:#111827;border:1px solid #d1d5db}}.badge{{display:inline-block;border-radius:999px;padding:6px 10px;background:#dcfce7;color:#166534;font-size:12px;font-weight:800}}@media(max-width:820px){{body{{padding:12px}}.grid{{grid-template-columns:1fr}}h1{{font-size:36px}}}}</style>
</head><body><div class=\"wrap\"><div class=\"hero\"><span class=\"badge\">Controlled SMB self-service MVP ready</span><h1>Repliq handles customer messages, bookings and business FAQs.</h1><p>Launch a workspace for a small or medium business, connect the calendar, and use Repliq as a text-first AI receptionist.</p><div class=\"actions\"><a class=\"btn\" href=\"{signup}\">Create workspace</a><a class=\"btn secondary\" href=\"/owner/login?tenant_id={tid}\">Owner login</a></div></div><div class=\"grid\"><div class=\"step\"><h2>1. Create workspace</h2><div class=\"muted\">Enter business name, owner email, timezone, language and basic working hours.</div></div><div class=\"step\"><h2>2. Finish setup</h2><div class=\"muted\">Owner account is created immediately. Calendar/channel setup remains controlled and visible in readiness checks.</div></div><div class=\"step\"><h2>3. Go live safely</h2><div class=\"muted\">Stage 78 launch lock, abuse protection, CSRF, billing gate and owner/admin separation remain active.</div></div></div><div class=\"card\"><h2>Launch scope</h2><p class=\"muted\">This is the working SMB SaaS path: public signup, owner workspace, billing visibility, and launch readiness. Enterprise features such as SSO/RBAC/audit/SLA/DR are later phases.</p></div></div></body></html>"""

def stage61_admin_auth_error(status_code: int, detail: str) -> JSONResponse:
    return JSONResponse(
        status_code=status_code,
        content={
            "ok": False,
            "stage": "62",
            "error": detail,
            "auth_model": "admin_session_or_shared_token_mvp",
            "accepted": {
                "login_page": "/admin/login",
                "headers": ["X-Repliq-Admin-Token", "Authorization: Bearer <token>"],
                "query": ["admin_token=<token>"],
                "session_cookie": STAGE62_ADMIN_SESSION_COOKIE_NAME,
                "legacy_cookie": STAGE61_ADMIN_COOKIE_NAME,
            },
            "note": "Admin surfaces are protected by Stage 62 admin session / Stage 61 shared token. Do not paste the token into chat logs.",
        },
        headers={"Cache-Control": "no-store"},
    )


@app.middleware("http")
async def stage61_admin_access_middleware(request: Request, call_next):
    path = (request.url.path or "").rstrip("/") or "/"
    token_from_query = stage61_query_token(request)
    query_token_valid = stage61_token_valid(token_from_query)

    candidate = stage61_request_token(request)
    admin_token_ok = stage61_token_valid(candidate)
    admin_session_ok = stage62_request_has_valid_session(request)

    if stage61_admin_access_enforcement_enabled() and stage61_path_requires_admin(path):
        if not stage61_admin_token_configured():
            return stage61_admin_auth_error(503, "admin_token_not_configured")
        if not (admin_token_ok or admin_session_ok):
            return stage61_admin_auth_error(401, "admin_token_required")
    elif stage71_owner_auth_enforcement_enabled() and stage71_path_requires_owner(path):
        if path in STAGE71_STRICT_OWNER_ONLY_EXACT_PATHS:
            owner_access = stage71_owner_request_access(request, path=path)
            if not owner_access.get("ok"):
                return stage71_strict_owner_auth_error(401, str(owner_access.get("error") or "owner_login_required"), tenant_id=owner_access.get("tenant_id") or request.query_params.get("tenant_id") or TENANT_ID_DEFAULT)
        # Super-admin sessions may open most owner surfaces for support/private demo, but
        # ordinary client access must pass the Stage 71 owner session + tenant binding.
        elif not (admin_token_ok or admin_session_ok):
            owner_access = stage71_owner_request_access(request, path=path)
            if not owner_access.get("ok"):
                return stage71_owner_auth_error(401, str(owner_access.get("error") or "owner_login_required"), tenant_id=owner_access.get("tenant_id") or request.query_params.get("tenant_id") or TENANT_ID_DEFAULT)

    if stage74_csrf_enforcement_enabled() and request.method.upper() in {"POST", "PUT", "PATCH", "DELETE"}:
        tenant_for_csrf = str(request.query_params.get("tenant_id") or "").strip()
        explicit_admin_token_ok = stage61_token_valid(stage61_request_non_cookie_token(request))
        if path in STAGE74_ADMIN_BROWSER_WRITE_PATHS:
            if not explicit_admin_token_ok and admin_session_ok:
                if not stage74_browser_write_protection_ok(request, scope="admin", tenant_id=tenant_for_csrf):
                    return stage74_csrf_error("admin", tenant_for_csrf)
        elif path in STAGE74_OWNER_BROWSER_WRITE_PATHS:
            if not (explicit_admin_token_ok or admin_session_ok):
                if stage71_request_owner_session_payload(request):
                    if not stage74_browser_write_protection_ok(request, scope="owner", tenant_id=tenant_for_csrf):
                        return stage74_csrf_error("owner", tenant_for_csrf)
        elif path in STAGE74_PUBLIC_BROWSER_WRITE_PATHS:
            if not stage74_browser_write_protection_ok(request, scope="public", tenant_id=tenant_for_csrf):
                return stage74_csrf_error("public", tenant_for_csrf, reason="cross_site_public_browser_write_blocked")

    response = await call_next(request)
    if query_token_valid:
        stage62_set_admin_session_cookie(response, tenant_id=(request.query_params.get("tenant_id") or TENANT_ID_DEFAULT))
    return response

# -------------------------
# HUMAN RESPONSE LAYER (2.6)
# -------------------------
def _pick_variant(options: List[str], fallback: str) -> str:
    cleaned = [str(x).strip() for x in options if str(x).strip()]
    return random.choice(cleaned) if cleaned else fallback

def _slot_labels_from_pending(pending: Dict[str, Any]) -> List[str]:
    labels: List[str] = []
    for iso in get_offered_slots(pending or {}):
        dtv = parse_dt_any_tz(iso)
        if dtv:
            labels.append(format_dt_short(dtv))
    return labels

def humanize_result(result: Dict[str, Any], conv: Optional[Dict[str, Any]], tenant: Dict[str, Any]) -> Dict[str, Any]:
    result = dict(result or {})
    conv = conv or {}
    tenant = tenant or {}
    lang = get_lang(result.get("lang") or conv.get("lang") or tenant.get("language") or "lv")
    state = conversation_state(conv)
    pending = conv.get("pending") or {}
    settings = tenant_settings(tenant, lang)
    service_text = text_mvp_localized_service_name(result.get("service") or pending.get("service_display") or "", lang)
    when_text = str(result.get("when") or result.get("datetime_text") or "").strip()
    slots = _slot_labels_from_pending(pending)

    def apply(text_value: str):
        result["msg_out"] = text_value
        result["reply_voice"] = text_value

    if result.get("preserve_text") or result.get("flow_preserved"):
        return result

    if result.get("status") == "greeting":
        if lang == "ru":
            apply(_pick_variant([
                "Здравствуйте! Чем могу помочь?",
                "Добрый день! Чем могу помочь?",
            ], result.get("msg_out") or "Здравствуйте! Чем могу помочь?"))
        elif lang == "en":
            apply(_pick_variant([
                "Hello! How can I help you today?",
                "Hi! How can I help?",
            ], result.get("msg_out") or "Hello! How can I help?"))
        else:
            apply(_pick_variant([
                "Labdien! Kā varu palīdzēt?",
                "Sveiki! Kā varu palīdzēt?",
            ], result.get("msg_out") or "Labdien! Kā varu palīdzēt?"))
        return result

    if result.get("status") == "booked" and when_text:
        if lang == "ru":
            apply(_pick_variant([
                f"Отлично, записал вас на {when_text}.",
                f"Готово, запись подтверждена на {when_text}.",
                f"Хорошо, подтверждаю запись на {when_text}.",
            ], result.get("msg_out") or f"Запись подтверждена на {when_text}."))
        elif lang == "en":
            apply(_pick_variant([
                f"Great, you are booked for {when_text}.",
                f"Done, your appointment is confirmed for {when_text}.",
            ], result.get("msg_out") or f"Your appointment is confirmed for {when_text}."))
        else:
            apply(_pick_variant([
                f"Lieliski, pierakstīju jūs uz {when_text}.",
                f"Gatavs, jūsu pieraksts ir apstiprināts uz {when_text}.",
                f"Labi, apstiprinu pierakstu uz {when_text}.",
            ], result.get("msg_out") or f"Pieraksts apstiprināts uz {when_text}."))
        return result

    if result.get("status") == "reschedule_wait" and when_text:
        if lang == "ru":
            apply(_pick_variant([
                f"Понял. Сейчас у вас запись на {when_text}. На какое время хотите перенести?",
                f"Хорошо, текущая запись стоит на {when_text}. Какое новое время вам удобно?",
            ], result.get("msg_out") or f"Текущая запись на {when_text}. На какое время перенести?"))
        elif lang == "en":
            apply(_pick_variant([
                f"Understood. Your current appointment is at {when_text}. What time would you like instead?",
                f"Okay, you are currently booked for {when_text}. What new time works for you?",
            ], result.get("msg_out") or f"Your appointment is at {when_text}. What time would you like instead?"))
        else:
            apply(_pick_variant([
                f"Sapratu. Pašlaik jums pieraksts ir {when_text}. Uz kuru laiku vēlaties pārcelt?",
                f"Labi, šobrīd jūsu pieraksts ir {when_text}. Kāds jaunais laiks jums derētu?",
            ], result.get("msg_out") or f"Pieraksts ir {when_text}. Uz kuru laiku pārcelt?"))
        return result

    if result.get("status") in {"holiday_closed", "min_notice"}:
        # keep clearer existing text but make it a little warmer
        if lang == "ru":
            apply(result.get("msg_out") or "К сожалению, на это время записать нельзя. Давайте подберём другой вариант.")
        elif lang == "en":
            apply(result.get("msg_out") or "Unfortunately, that time is not available. Let me suggest another option.")
        else:
            apply(result.get("msg_out") or "Diemžēl šis laiks nav pieejams. Atradīsim citu variantu.")
        return result

    if result.get("status") in {"busy", "need_more"} and state == STATE_AWAITING_SERVICE:
        if lang == "ru":
            apply(_pick_variant([
                "Конечно. На какую услугу вас записать?",
                "Хорошо. Что именно хотите сделать?",
                "Подскажите, на какую услугу хотите записаться?",
            ], result.get("msg_out") or "На какую услугу вас записать?"))
        elif lang == "en":
            apply(_pick_variant([
                "Of course. Which service would you like to book?",
                "Sure — what would you like to book?",
            ], result.get("msg_out") or "Which service would you like to book?"))
        else:
            apply(_pick_variant([
                "Protams. Uz kādu pakalpojumu vēlaties pierakstīties?",
                "Labi. Pasakiet, lūdzu, kuru pakalpojumu vēlaties.",
                "Uz kuru pakalpojumu jūs pierakstīt?",
            ], result.get("msg_out") or "Uz kādu pakalpojumu vēlaties pierakstīties?"))
        return result

    if result.get("status") in {"busy", "need_more"} and state == STATE_AWAITING_DATE:
        if lang == "ru":
            apply(_pick_variant([
                "Хорошо. На какой день вас записать?",
                "Отлично. Какая дата вам удобна?",
                "Подскажите, на какой день хотите запись?",
            ], result.get("msg_out") or "На какой день вас записать?"))
        elif lang == "en":
            apply(_pick_variant([
                "Sure. Which day would work for you?",
                "Okay. What date would you prefer?",
            ], result.get("msg_out") or "Which day would work for you?"))
        else:
            apply(_pick_variant([
                "Labi. Uz kuru dienu vēlaties pierakstīties?",
                "Skaidrs. Kurš datums jums būtu ērts?",
                "Pasakiet, lūdzu, kuru dienu vēlaties.",
            ], result.get("msg_out") or "Uz kuru dienu vēlaties pierakstīties?"))
        return result

    if result.get("status") in {"busy", "need_more"} and state == STATE_AWAITING_TIME and slots:
        if len(slots) >= 3:
            joined = ", ".join(slots[:3])
        else:
            joined = ", ".join(slots[:2])
        if lang == "ru":
            apply(_pick_variant([
                f"Могу предложить такие варианты: {joined}. Что вам удобнее?",
                f"Есть несколько свободных вариантов: {joined}. Какое время подойдёт?",
                f"Свободно вот так: {joined}. Что выбираем?",
            ], result.get("msg_out") or f"Доступны варианты: {joined}."))
        elif lang == "en":
            apply(_pick_variant([
                f"I can offer these times: {joined}. What works best for you?",
                f"There are a few available options: {joined}. Which one suits you?",
            ], result.get("msg_out") or f"Available times: {joined}."))
        else:
            apply(_pick_variant([
                f"Varu piedāvāt šādus laikus: {joined}. Kurš jums der?",
                f"Ir pieejami vairāki varianti: {joined}. Ko izvēlamies?",
                f"Brīvie laiki ir šādi: {joined}. Kurš jums būtu ērtāks?",
            ], result.get("msg_out") or f"Pieejamie laiki: {joined}."))
        return result

    if result.get("status") == "need_more" and state == STATE_AWAITING_CONFIRM and (when_text or str(conv.get("datetime_iso") or "").strip()):
        if not when_text:
            _dtc = parse_dt_any_tz(str(conv.get("datetime_iso") or "").strip())
            when_text = format_dt_short(_dtc) if _dtc else when_text
        if lang == "ru":
            apply(_pick_variant([
                f"Тогда подтверждаем запись на {when_text}?",
                f"Подтверждаем время {when_text}?",
            ], result.get("msg_out") or f"Подтвердить запись на {when_text}?"))
        elif lang == "en":
            apply(_pick_variant([
                f"Shall I confirm the booking for {when_text}?",
                f"Would you like me to confirm {when_text}?",
            ], result.get("msg_out") or f"Confirm the booking for {when_text}?"))
        else:
            apply(_pick_variant([
                f"Tad apstiprinām pierakstu uz {when_text}?",
                f"Vai apstiprināt laiku {when_text}?",
            ], result.get("msg_out") or f"Apstiprināt pierakstu uz {when_text}?"))
        return result

    return result


# -------------------------
# STAGE 25 — AI RESPONSE COMPOSER
# -------------------------
def ai_response_composer_enabled(channel: str = "", source: str = "runtime") -> bool:
    flag = os.getenv("AI_RESPONSE_COMPOSER_ENABLED", "").strip().lower()
    if flag in {"0", "false", "no", "off", "disabled"}:
        return False
    if flag in {"1", "true", "yes", "on", "enabled"}:
        return bool(OPENAI_API_KEY)
    # Default: follow the existing LLM intelligence switch.
    return bool(LLM_INTELLIGENCE_ENABLED and OPENAI_API_KEY)


def _safe_compose_text(value: Any, max_len: int = 900) -> str:
    txt = str(value or "").strip()
    if not txt:
        return ""
    txt = re.sub(r"\s+", " ", txt).strip()
    return txt[:max_len]


def _looks_like_internal_prompt_leak(text_value: Any) -> bool:
    """Guard customer replies from leaking internal prompt/config labels."""
    low = str(text_value or "").strip().lower()
    if not low:
        return False
    return bool(re.search(r"\b(business_memory(?:_[a-z]{2})?|faq(?:_[a-z]{2})?|booking_rules(?:_[a-z]{2})?|env_memory)\s*:", low))


def _composer_allowed_for_result(result: Dict[str, Any]) -> bool:
    status = str((result or {}).get("status") or "").strip().lower()
    if not status:
        return False
    # Do not rewrite account/system blocking or deliberately preserved technical recovery text.
    if status in {"blocked"}:
        return False
    if (result or {}).get("preserve_text") or (result or {}).get("flow_preserved"):
        return False
    base_text = str((result or {}).get("msg_out") or (result or {}).get("reply_voice") or "").strip()
    if not base_text:
        return False
    return status in {
        "greeting",
        "identity",
        "info",
        "need_more",
        "busy",
        "holiday_closed",
        "min_notice",
        "reschedule_wait",
        "booked",
        "booking_failed",
        "recovery",
    }


def _composer_style_for_lang(lang: str) -> str:
    lang = get_lang(lang)
    if lang == "ru":
        return "Пиши на русском. Тон: живой, спокойный, как администратор салона. Без канцелярита."
    if lang == "en":
        return "Write in English. Tone: warm, concise, and receptionist-like. No corporate wording."
    return "Raksti latviski. Tonis: dzīvs, mierīgs un pieklājīgs kā salona administratoram. Bez formālas, robotiskas valodas."


def ai_response_composer(
    result: Dict[str, Any],
    conv: Optional[Dict[str, Any]],
    tenant: Dict[str, Any],
    channel: str = "",
    source: str = "runtime",
) -> Dict[str, Any]:
    """Rewrite only the final customer-facing text.

    Safety contract:
    - never changes status, state, service, datetime, offered slots, or booking actions;
    - falls back to the current rule-based text on any error;
    - usage warnings are added after this layer, so AI cannot rewrite billing/limit notices.
    """
    result = dict(result or {})
    if not ai_response_composer_enabled(channel, source):
        return result
    if not _composer_allowed_for_result(result):
        return result

    conv = conv or {}
    tenant = tenant or {}
    lang = get_lang(result.get("lang") or conv.get("lang") or tenant.get("language") or "lv")
    state = conversation_state(conv)
    pending = conv.get("pending") or {}
    base_text = str(result.get("msg_out") or result.get("reply_voice") or "").strip()
    if not base_text:
        return result

    offered_slots = _slot_labels_from_pending(pending)
    settings = tenant_settings(tenant, lang)
    memory = tenant_business_memory(tenant, lang)

    composer_payload = {
        "language": lang,
        "channel": str(channel or "").strip().lower() or "unknown",
        "status": str(result.get("status") or "").strip(),
        "state": state,
        "business_name": _safe_compose_text(settings.get("biz_name"), 120),
        "business_type": _safe_compose_text(settings.get("business_type"), 80),
        "current_reply": _safe_compose_text(base_text, 900),
        "service": _safe_compose_text(result.get("service") or result.get("service_display") or pending.get("service_display") or conv.get("service"), 160),
        "when": _safe_compose_text(result.get("when") or result.get("datetime_text") or conv.get("datetime_iso"), 160),
        "offered_slots": offered_slots[:3],
        "pending_keys": sorted([str(k) for k in pending.keys()])[:30] if isinstance(pending, dict) else [],
        "business_memory": _safe_compose_text(memory, 700),
    }

    system_prompt = (
        "You are the Stage 25 AI Response Composer for Repliq, an AI receptionist SaaS. "
        "Your only job is to rewrite the already-decided customer-facing reply so it sounds natural and human. "
        "Never change facts, dates, times, services, prices, offered slots, booking status, or the question being asked. "
        "Do not add new times, do not invent availability, do not promise actions that are not in current_reply. "
        "Keep the reply concise: usually 1 sentence, maximum 2 short sentences. "
        "Return strict JSON only with this key: msg_out. "
        + _composer_style_for_lang(lang)
    )
    user_prompt = json.dumps(composer_payload, ensure_ascii=False, default=str)

    try:
        raw = openai_chat_json(system_prompt, user_prompt)
        composed = str((raw or {}).get("msg_out") or "").strip()
        composed = re.sub(r"\s+\n", "\n", composed).strip()
        if not composed:
            return result
        if _looks_like_internal_prompt_leak(composed):
            return result
        if len(composed) > 500:
            return result
        # Guardrail: if the original answer contained concrete offered slots, the composed answer must preserve them.
        for slot_label in offered_slots[:3]:
            if slot_label and slot_label not in composed and slot_label in base_text:
                return result
        result["msg_out"] = composed
        result["reply_voice"] = composed
        result["ai_composed"] = True
        result["ai_composer_stage"] = "stage_25"
        return result
    except Exception as e:
        log.error("ai_response_composer_failed err=%s", e)
        return result


# -------------------------
# STAGE 25.5 — CONVERSATIONAL CLOSURE LAYER
# -------------------------
def _closure_normalized_text(text_: Optional[str]) -> str:
    low = _normalize_phrase_text(text_)
    low = low.replace("🙏", "").replace("🙂", "").replace("😊", "").strip()
    return re.sub(r"\s+", " ", low).strip()


def is_thank_you_text(text_: Optional[str], lang: str) -> bool:
    low = _closure_normalized_text(text_)
    if not low:
        return False
    phrases = {
        "lv": {"paldies", "liels paldies", "paldies jums", "paldies tev", "super paldies", "ok paldies", "labi paldies"},
        "ru": {"спасибо", "спасибо вам", "большое спасибо", "спс", "благодарю", "ок спасибо", "хорошо спасибо"},
        "en": {"thanks", "thank you", "thank you very much", "many thanks", "ok thanks", "great thanks"},
    }
    allowed = set().union(*phrases.values())
    allowed.update(phrases.get(get_lang(lang), set()))
    if low in allowed:
        return True
    return any(low.startswith(p + " ") or low.endswith(" " + p) for p in allowed if p)


def is_goodbye_text(text_: Optional[str], lang: str) -> bool:
    low = _closure_normalized_text(text_)
    if not low:
        return False
    phrases = {
        "lv": {"atā", "ata", "uz redzēšanos", "uz redzesanos", "visu labu", "līdz vēlākam", "lidz velakam"},
        "ru": {"пока", "до свидания", "до встречи", "всего доброго", "хорошего дня"},
        "en": {"bye", "goodbye", "see you", "see you soon", "have a nice day"},
    }
    allowed = set().union(*phrases.values())
    allowed.update(phrases.get(get_lang(lang), set()))
    return low in allowed or any(low.startswith(p + " ") for p in allowed if p)


def is_positive_closure_ack_text(text_: Optional[str], lang: str) -> bool:
    low = _closure_normalized_text(text_)
    if not low:
        return False
    phrases = {
        "lv": {"labi", "super", "skaidrs", "forši", "forsi", "ok", "okej", "ideāli", "ideali"},
        "ru": {"ок", "хорошо", "супер", "понял", "поняла", "отлично", "ладно"},
        "en": {"ok", "okay", "great", "perfect", "sounds good", "got it", "alright"},
    }
    allowed = set().union(*phrases.values())
    allowed.update(phrases.get(get_lang(lang), set()))
    return low in allowed


def closure_reply_text(lang: str, closure_type: str, conv: Optional[Dict[str, Any]] = None, tenant: Optional[Dict[str, Any]] = None) -> str:
    lang = get_lang(lang)
    conv = conv or {}
    tenant = tenant or {}
    dtv = parse_dt_any_tz(str(conv.get("datetime_iso") or "").strip())
    when_text = format_dt_short(dtv) if dtv else ""
    state = conversation_state(conv)

    if state == STATE_BOOKED and when_text:
        if lang == "ru":
            if closure_type == "goodbye":
                return f"До встречи! Ждём вас {when_text}."
            return f"Пожалуйста! Ждём вас {when_text}."
        if lang == "en":
            if closure_type == "goodbye":
                return f"See you then! We’ll be expecting you on {when_text}."
            return f"You’re welcome! We’ll be expecting you on {when_text}."
        if closure_type == "goodbye":
            return f"Uz tikšanos! Gaidīsim jūs {when_text}."
        return f"Lūdzu! Gaidīsim jūs {when_text}."

    if state == STATE_CANCELLED:
        if lang == "ru":
            return "Пожалуйста! Если понадобится новая запись, напишите — помогу подобрать время."
        if lang == "en":
            return "You’re welcome! If you need a new appointment, just message me and I’ll help."
        return "Lūdzu! Ja vajadzēs jaunu pierakstu, uzrakstiet — palīdzēšu atrast laiku."

    if closure_type == "goodbye":
        if lang == "ru":
            return "До свидания! Хорошего дня."
        if lang == "en":
            return "Goodbye! Have a nice day."
        return "Uz redzēšanos! Lai jauka diena."

    if lang == "ru":
        return "Пожалуйста! Рад помочь."
    if lang == "en":
        return "You’re welcome! Happy to help."
    return "Lūdzu! Prieks palīdzēt."


def maybe_conversational_closure_result(
    tenant_id: str,
    user_key: str,
    msg: str,
    lang: str,
    conv: Dict[str, Any],
    tenant: Dict[str, Any],
) -> Optional[Dict[str, Any]]:
    if not (msg or "").strip():
        return None

    state = conversation_state(conv or {})
    pending = (conv or {}).get("pending") or {}

    # Never steal confirmations or active slot/service selection. In active booking
    # states, words like "ok" and "labi" may be real confirmation signals.
    if state in ACTIVE_BOOKING_STATES or state == STATE_POST_BOOKING_UPSELL:
        return None

    closure_type = None
    if is_thank_you_text(msg, lang):
        closure_type = "thanks"
    elif is_goodbye_text(msg, lang):
        closure_type = "goodbye"
    elif state in {STATE_BOOKED, STATE_CANCELLED} and is_positive_closure_ack_text(msg, lang):
        closure_type = "ack"

    if not closure_type:
        return None

    # After booking/cancellation, clear stale pending flags so the next polite
    # message does not accidentally re-open the booking state machine.
    if state in {STATE_BOOKED, STATE_CANCELLED} and pending:
        conv["pending"] = None
        db_save_conversation(tenant_id, user_key, conv)

    reply = closure_reply_text(lang, closure_type, conv, tenant)
    return {
        "status": "info",
        "reply_voice": reply,
        "msg_out": reply,
        "lang": lang,
        "preserve_text": True,
        "closure_type": closure_type,
    }


# -------------------------
# STAGE 33 — SOFT CONVERSATIONAL UX LAYER
# -------------------------
def stage33_soft_ux_enabled(channel: str = "", source: str = "runtime") -> bool:
    flag = os.getenv("STAGE33_SOFT_UX_ENABLED", "").strip().lower()
    if flag in {"0", "false", "no", "off", "disabled"}:
        return False
    return True


def _stage33_join_options(lang: str, items: List[str]) -> str:
    cleaned = [str(x).strip() for x in items if str(x).strip()]
    if not cleaned:
        return ""
    if len(cleaned) == 1:
        return cleaned[0]
    sep = " или " if get_lang(lang) == "ru" else " or " if get_lang(lang) == "en" else " vai "
    return ", ".join(cleaned[:-1]) + sep + cleaned[-1]


def _stage33_when_text(result: Dict[str, Any], conv: Dict[str, Any], pending: Dict[str, Any]) -> str:
    explicit = str((result or {}).get("when") or (result or {}).get("datetime_text") or "").strip()
    if explicit:
        return explicit
    for value in [
        (pending or {}).get("confirm_slot_iso"),
        (pending or {}).get("candidate_datetime_iso"),
        (conv or {}).get("datetime_iso"),
    ]:
        dtv = parse_dt_any_tz(str(value or "").strip())
        if dtv:
            return format_dt_short(dtv)
    return ""


def _stage33_requested_busy_hint(text_: str, lang: str) -> bool:
    low = _normalize_phrase_text(text_)
    folded = _fold_match_text(text_)
    markers = [
        "занято", "занят", "уже занято", "aiznemts", "aizņemts", "nav pieejams",
        "taken", "already taken", "not available", "busy",
    ]
    return any(m in low or m in folded for m in markers)


def stage33_soft_conversational_ux(
    result: Dict[str, Any],
    conv: Optional[Dict[str, Any]],
    tenant: Dict[str, Any],
    channel: str = "",
    source: str = "runtime",
) -> Dict[str, Any]:
    """Final deterministic wording layer for Stage 33.

    Safety contract:
    - only rewrites msg_out/reply_voice;
    - never changes status, state, calendar actions, service, datetime or offered slots;
    - keeps all concrete offered slot labels in the customer-facing reply.
    """
    result = dict(result or {})
    if not stage33_soft_ux_enabled(channel, source):
        return result

    # Stage 46: some upstream actions carry exact, action-specific wording
    # (notably completed reschedules). Preserve those replies so the soft
    # UX layer cannot turn "record moved" into a generic new-booking message.
    if result.get("preserve_text") or result.get("reschedule_finalized"):
        return result

    # Stage 38.3: side-question FAQ answers inside an active booking flow
    # already include both the business-memory answer and the preserved flow
    # follow-up. Do not let the final soft UX layer collapse that combined
    # answer back into a generic slot prompt.
    if result.get("flow_preserved") or result.get("stage38_business_faq"):
        return result

    status = str(result.get("status") or "").strip().lower()
    if status in {"blocked", "booking_failed", "recovery"}:
        return result

    conv = conv or {}
    tenant = tenant or {}
    pending = conv.get("pending") or {}
    lang = get_lang(result.get("lang") or conv.get("lang") or tenant.get("language") or "lv")
    state = conversation_state(conv)
    base_text = str(result.get("msg_out") or result.get("reply_voice") or "").strip()
    slots = _slot_labels_from_pending(pending)
    when_text = _stage33_when_text(result, conv, pending)
    service_text = text_mvp_localized_service_name(result.get("service") or result.get("service_display") or pending.get("service_display") or "", lang)

    def apply(text_value: str) -> Dict[str, Any]:
        text_value = str(text_value or "").strip()
        if not text_value:
            return result
        for slot_label in slots[:4]:
            if slot_label and slot_label not in text_value:
                return result
        result["msg_out"] = text_value
        result["reply_voice"] = text_value
        result["stage33_soft_ux"] = True
        return result

    if status == "booked" and when_text:
        if lang == "ru":
            return apply(_pick_variant([
                f"Готово, записал вас на {when_text}. Будем ждать вас!",
                f"Отлично, запись подтверждена на {when_text}. До встречи!",
                f"Супер, закрепил за вами время {when_text}.",
            ], base_text or f"Запись подтверждена на {when_text}."))
        if lang == "en":
            return apply(_pick_variant([
                f"Done — you’re booked for {when_text}. See you then!",
                f"Great, your appointment is confirmed for {when_text}.",
                f"Perfect, I’ve reserved {when_text} for you.",
            ], base_text or f"Your appointment is confirmed for {when_text}."))
        return apply(_pick_variant([
            f"Gatavs, pierakstīju jūs uz {when_text}. Gaidīsim jūs!",
            f"Lieliski, pieraksts apstiprināts uz {when_text}. Uz tikšanos!",
            f"Super, rezervēju jums laiku {when_text}.",
        ], base_text or f"Pieraksts apstiprināts uz {when_text}."))

    if status in {"need_more", "busy", "min_notice", "holiday_closed"} and state == STATE_AWAITING_TIME and slots:
        joined = _stage33_join_options(lang, slots[:4])
        busy_hint = _stage33_requested_busy_hint(base_text, lang) or status in {"busy", "min_notice", "holiday_closed"}
        if lang == "ru":
            text_value = (
                f"На запрошенное время не получается, но могу предложить: {joined}. Какой вариант вам удобнее?"
                if busy_hint else
                f"Нашёл такие варианты: {joined}. Какой вам больше подходит?"
            )
        elif lang == "en":
            text_value = (
                f"That requested time doesn’t work, but I can offer: {joined}. Which one suits you best?"
                if busy_hint else
                f"I found these options: {joined}. Which one works best for you?"
            )
        else:
            text_value = (
                f"Uz prasīto laiku nesanāk, bet varu piedāvāt: {joined}. Kurš variants jums der?"
                if busy_hint else
                f"Atradu šādus variantus: {joined}. Kurš jums būtu ērtāks?"
            )
        return apply(text_value)

    if status == "need_more" and state == STATE_AWAITING_CONFIRM and when_text:
        if lang == "ru":
            service_part = f" на услугу «{service_text}»" if service_text else ""
            return apply(_pick_variant([
                f"Это время свободно — записываем вас{service_part} на {when_text}?",
                f"Можем поставить запись на {when_text}. Подтверждаем?",
                f"{when_text} подходит — закрепить это время за вами?",
            ], base_text or f"Подтвердить запись на {when_text}?"))
        if lang == "en":
            service_part = f" for {service_text}" if service_text else ""
            return apply(_pick_variant([
                f"That time is available — shall I book you{service_part} for {when_text}?",
                f"We can do {when_text}. Should I confirm it?",
                f"{when_text} works — would you like me to reserve it?",
            ], base_text or f"Confirm the booking for {when_text}?"))
        service_part = f" uz {service_text}" if service_text else ""
        return apply(_pick_variant([
            f"Šis laiks ir pieejams — pierakstām jūs{service_part} uz {when_text}?",
            f"Varam jūs pierakstīt uz {when_text}. Apstiprinām?",
            f"{when_text} der — rezervēt šo laiku jums?",
        ], base_text or f"Apstiprināt pierakstu uz {when_text}?"))

    if status in {"need_more", "busy"} and state == STATE_AWAITING_SERVICE:
        if lang == "ru":
            return apply(_pick_variant([
                "Конечно. Подскажите, какую услугу хотите выбрать?",
                "Хорошо, помогу с записью. Какая услуга нужна?",
                "Давайте подберём время. Сначала уточню услугу — что хотите сделать?",
            ], base_text or "На какую услугу вас записать?"))
        if lang == "en":
            return apply(_pick_variant([
                "Of course. Which service would you like to book?",
                "Sure, I can help with that. What service do you need?",
                "Let’s find a time for you. Which service should I book?",
            ], base_text or "Which service would you like to book?"))
        return apply(_pick_variant([
            "Protams. Kuru pakalpojumu vēlaties izvēlēties?",
            "Labi, palīdzēšu ar pierakstu. Kāds pakalpojums nepieciešams?",
            "Atradīsim jums piemērotu laiku. Vispirms — kuru pakalpojumu vēlaties?",
        ], base_text or "Uz kādu pakalpojumu vēlaties pierakstīties?"))

    if status in {"need_more", "busy"} and state == STATE_AWAITING_DATE:
        if lang == "ru":
            return apply(_pick_variant([
                "Хорошо. На какой день посмотрим запись?",
                "Понял. Какая дата вам была бы удобна?",
                "Давайте подберём день. Когда вам удобнее?",
            ], base_text or "На какой день вас записать?"))
        if lang == "en":
            return apply(_pick_variant([
                "Sure. Which day should I check?",
                "Got it. What date would work for you?",
                "Let’s pick a day first. When would be convenient?",
            ], base_text or "Which day would work for you?"))
        return apply(_pick_variant([
            "Labi. Uz kuru dienu skatāmies pierakstu?",
            "Sapratu. Kurš datums jums būtu ērts?",
            "Vispirms izvēlēsimies dienu. Kad jums būtu ērtāk?",
        ], base_text or "Uz kuru dienu vēlaties pierakstīties?"))

    if status == "reschedule_wait" and when_text:
        if lang == "ru":
            return apply(f"Понял. Сейчас запись стоит на {when_text}. На какое новое время хотите перенести?")
        if lang == "en":
            return apply(f"Understood. Your current appointment is at {when_text}. What new time would work better?")
        return apply(f"Sapratu. Pašlaik pieraksts ir {when_text}. Uz kuru jauno laiku vēlaties pārcelt?")

    return result


