@app.post("/public/signup")
async def stage72_public_signup_submit(request: Request):
    try:
        data = await request.json()
    except Exception:
        raw = (await request.body()).decode("utf-8", errors="ignore")
        data = {k: v[-1] if v else "" for k, v in urllib.parse.parse_qs(raw).items()}
    data = dict(data or {})
    owner_email = stage71_normalize_email(data.get("owner_email") or data.get("email") or "")

    def reject(status_code: int, error: str):
        rejected_tenant_id = str(data.get("tenant_slug") or data.get("tenant_id") or "")
        stage72_record_public_signup_event(request, owner_email=owner_email, tenant_id=rejected_tenant_id, status="rejected", reason=error)
        stage75_record_abuse_event(request, bucket="public_signup", subject=f"{rejected_tenant_id}:{owner_email}", tenant_id=rejected_tenant_id, status="rejected", reason=error)
        return JSONResponse(status_code=status_code, content={"ok": False, "stage": "72", "error": error, "public_saas_ready": False, "secret_values_exposed": False, "abuse_protection": {"stage": "75", "ip_hash_exposed": False, "subject_hash_exposed": False}}, headers={"Cache-Control": "no-store"})

    if not stage72_public_signup_enabled():
        return reject(503, "public_signup_disabled")
    if stage72_public_signup_honeypot_value(data):
        return reject(400, "public_signup_rejected")
    if not stage72_bool_payload(data.get("accepted_terms")):
        return reject(400, "accepted_terms_required")
    if not stage71_valid_email(owner_email):
        return reject(400, "owner_email_required_or_invalid")
    rate = stage72_public_signup_rate_limit_check(request, owner_email)
    if not rate.get("ok"):
        return reject(429, str(rate.get("reason") or "public_signup_rate_limited"))
    abuse_gate = stage75_public_signup_gate(request, owner_email=owner_email, tenant_id=str(data.get("tenant_slug") or data.get("tenant_id") or ""))
    if not abuse_gate.get("ok"):
        stage75_record_abuse_event(request, bucket="public_signup", subject=f"{str(data.get('tenant_slug') or data.get('tenant_id') or '')}:{owner_email}", tenant_id=str(data.get("tenant_slug") or data.get("tenant_id") or ""), status="blocked", reason=str(abuse_gate.get("reason") or "rate_limited"))
        return stage75_abuse_error(abuse_gate, tenant_id=str(data.get("tenant_slug") or data.get("tenant_id") or ""))

    create_payload = dict(data)
    create_payload["owner_email"] = owner_email
    try:
        created = onboarding_create_tenant(create_payload)
        tenant_id = str(created.get("tenant_id") or "").strip()
        if not tenant_id:
            return reject(500, "tenant_create_missing_tenant_id")
        owner_bootstrap = stage71_bootstrap_owner_for_tenant(tenant_id=tenant_id, owner_email=owner_email, display_name=str(data.get("owner_name") or data.get("business_name") or "").strip(), regenerate_code=True)
    except HTTPException as e:
        detail = e.detail if isinstance(e.detail, str) else json.dumps(e.detail, ensure_ascii=False)
        return reject(int(e.status_code or 400), detail[:160])
    except ValueError as e:
        return reject(400, str(e))
    except Exception as e:
        log.error("stage72_public_signup_failed err=%s", e)
        return reject(500, e.__class__.__name__)

    stage72_record_public_signup_event(request, owner_email=owner_email, tenant_id=tenant_id, status="created", reason="ok")
    stage75_record_abuse_event(request, bucket="public_signup", subject=f"{tenant_id}:{owner_email}", tenant_id=tenant_id, status="created", reason="ok")
    next_path = f"/owner/get-started/ui?tenant_id={urllib.parse.quote(tenant_id)}"
    content = {
        "ok": True,
        "stage": "72",
        "launch_ux_stage": "79",
        "signup_owner_workspace_e2e_stage": "93",
        "status": "ok",
        "tenant_id": tenant_id,
        "business_name": created.get("business_name"),
        "owner_email": owner_email,
        "owner_session_created": True,
        "owner_login_code": owner_bootstrap.get("login_code"),
        "owner_login_code_returned_once": bool(owner_bootstrap.get("login_code")),
        "owner_magic_link_url": owner_bootstrap.get("magic_link_url"),
        "owner_magic_link_token": owner_bootstrap.get("magic_link_token"),
        "owner_magic_link_token_returned_once": bool(owner_bootstrap.get("magic_link_token")),
        "email_verification_magic_link_foundation_ready": bool(owner_bootstrap.get("magic_link_token")),
        "login_code_hash_exposed": False,
        "magic_link_token_hash_exposed": False,
        "secret_values_exposed": False,
        "public_saas_ready": False,
        "public_saas_ready_reason": "workspace_created_tenant_onboarding_required",
        "platform_public_saas_ready": True,
        "platform_public_saas_ready_source": "stage78_final_public_saas_readiness_lock_closed",
        "maturity_phase": STAGE79_MATURITY_TARGET,
        "tenant_launch_state": "workspace_created_owner_onboarding_required",
        "onboarding": created.get("onboarding"),
        "readiness": created.get("readiness"),
        "links": {
            "owner_get_started": next_path,
            "owner_workspace": f"/owner/workspace/ui?tenant_id={urllib.parse.quote(tenant_id)}",
            "owner_dashboard": f"/owner/dashboard/ui?tenant_id={urllib.parse.quote(tenant_id)}",
            "owner_setup_health": f"/owner/setup-health/ui?tenant_id={urllib.parse.quote(tenant_id)}",
            "owner_launch_review": f"/owner/launch-review/ui?tenant_id={urllib.parse.quote(tenant_id)}",
            "owner_account": f"/owner/account/ui?tenant_id={urllib.parse.quote(tenant_id)}",
            "owner_login": f"/owner/login?tenant_id={urllib.parse.quote(tenant_id)}",
            "owner_magic_login": f"/owner/magic-login?tenant_id={urllib.parse.quote(tenant_id)}",
            "owner_billing": f"/owner/billing/ui?tenant_id={urllib.parse.quote(tenant_id)}",
            "owner_session": f"/owner/session?tenant_id={urllib.parse.quote(tenant_id)}",
            "owner_logout": "/owner/logout",
        },
        "post_signup_handoff": {"stage": "93", "owner_session_active": True, "entrypoint": next_path, "strict_owner_session_only": True, "admin_links_exposed": False, "secret_values_rendered_in_handoff_ui": False},
        "super_admin_setup_links_exposed_to_public_signup": False,
        "rate_limit": {"ip_hash_exposed": False, "hourly_limit": stage72_public_signup_hourly_limit(), "email_daily_limit": stage72_public_signup_email_daily_limit()},
        "abuse_protection": {"stage": "75", "enabled": bool(stage75_abuse_protection_enabled()), "ip_hash_exposed": False, "subject_hash_exposed": False},
        "email_verification": {"stage": "76", "magic_link_foundation_ready": bool(owner_bootstrap.get("magic_link_token")), "email_delivery_provider_configured": bool(stage76_email_delivery_provider_configured()), "email_delivery_attempted": False, "token_hash_exposed": False, "raw_token_stored": False},
        "note": "Stage 93 sends the newly authenticated owner to a strict owner-only get-started handoff. One-time backup login code and magic link/token may still be returned for setup, but public and owner handoff UIs hide raw secret values from technical details.",
    }
    response = JSONResponse(content=content, headers={"Cache-Control": "no-store"})
    stage71_set_owner_session_cookie(response, owner_email=owner_email, tenant_id=tenant_id, role="owner")
    return response


